export enum FermenterStatus {
  IDLE = 'Inativo',
  ACTIVE = 'Fermentando',
  COLD_CRASH = 'Cold Crash',
  DIACETYL_REST = 'Descanso de Diacetil',
  CARBONATION = 'Carbonatação Forçada'
}

export enum BeerStyle {
  IPA = 'IPA',
  STOUT = 'Stout',
  LAGER = 'Lager',
  PALE_ALE = 'Pale Ale',
  NEIPA = 'NEIPA',
  WHEAT = 'Wheat'
}

export interface ISpindelData {
  gravity: number; // Specific Gravity (e.g., 1.050)
  temperature: number; // Celsius
  battery: number; // Volts
  angle: number; // Tilt angle
  rssi: number; // Wifi strength dBm
  lastUpdate: string; // ISO timestamp
}

export interface Reading {
  timestamp: string;
  beerTemp: number;
  fridgeTemp: number;
  targetTemp: number;
  gravity: number;
}

export interface Fermenter {
  id: string;
  name: string;
  status: FermenterStatus;
  beerName: string;
  style: BeerStyle;
  startDate: string;
  og: number; // Original Gravity
  volume: number; // Liters
  targetTemp: number;
  readings: Reading[];
  currentDevice: ISpindelData;
}

import { Fermenter, FermenterStatus, BeerStyle, Reading } from '../types';

const generateReadings = (days: number, startOg: number): Reading[] => {
  const readings: Reading[] = [];
  const now = new Date();
  let currentGravity = startOg;

  for (let i = days * 24; i >= 0; i--) { // Hourly readings for X days
    const time = new Date(now.getTime() - i * 60 * 60 * 1000);
    const progress = 1 - (i / (days * 24));

    // Simulate fermentation curve (exponential decay of gravity)
    if (currentGravity > 1.010) {
        currentGravity = startOg - ((startOg - 1.010) * Math.pow(progress, 0.5));
    }

    readings.push({
      timestamp: time.toISOString(),
      beerTemp: 19 + (Math.random() * 0.5 - 0.25), // Fluctuation around 19C
      fridgeTemp: 18.5 + (Math.sin(i / 2) * 1.5), // Compressor cycling
      targetTemp: 19.0,
      gravity: Number(currentGravity.toFixed(3))
    });
  }
  return readings;
};

