import React, { useState } from 'react';
import { Brain, Sparkles, Loader2, MessageSquare } from 'lucide-react';
import { Fermenter } from '../types';
import { getBrewingInsights } from '../services/geminiService';
import ReactMarkdown from 'react-markdown';

interface GeminiAdvisorProps {
  fermenter: Fermenter;
}

export const GeminiAdvisor: React.FC<GeminiAdvisorProps> = ({ fermenter }) => {
  const [insight, setInsight] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleAskAI = async () => {
    setLoading(true);
    const result = await getBrewingInsights(fermenter);
    setInsight(result);
    setLoading(false);
  };

  return (
    <div className="bg-gradient-to-br from-indigo-900/40 to-slate-900 border border-indigo-500/30 rounded-xl p-6 shadow-lg relative overflow-hidden">
      {/* Background decoration */}
      <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none">
        <Brain size={120} />
      </div>

      <div className="relative z-10">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
            <Sparkles className="text-yellow-400" size={20} />
            <h3 className="text-lg font-bold text-white">Mestre Cervejeiro AI</h3>
          </div>
          {!insight && (
            <button
              onClick={handleAskAI}
              disabled={loading}
              className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg transition-all disabled:opacity-50 text-sm font-medium"
            >
              {loading ? <Loader2 className="animate-spin" size={16} /> : <MessageSquare size={16} />}
              {loading ? "Analisando..." : "Analisar Fermentação"}
            </button>
          )}
        </div>

        {insight ? (
          <div className="bg-slate-800/60 rounded-lg p-4 text-slate-200 text-sm leading-relaxed border border-indigo-500/20 max-h-[300px] overflow-y-auto custom-scrollbar">
            <ReactMarkdown 
                components={{
                    strong: ({node, ...props}) => <span className="font-bold text-indigo-300" {...props} />,
                    ul: ({node, ...props}) => <ul className="list-disc pl-4 space-y-1 my-2" {...props} />,
                    li: ({node, ...props}) => <li className="text-slate-300" {...props} />
                }}
            >
                {insight}
            </ReactMarkdown>
            <button 
                onClick={() => setInsight(null)}
                className="mt-4 text-xs text-indigo-400 hover:text-indigo-300 underline"
            >
                Nova Análise
            </button>
          </div>
        ) : (
          <p className="text-slate-400 text-sm max-w-md">
            Utilize a inteligência artificial do Gemini para analisar as curvas de temperatura e gravidade, identificar paradas de fermentação e sugerir correções de perfil.
          </p>
        )}
      </div>
    </div>
  );
};

import React from 'react';
import { Fermenter, FermenterStatus } from '../types';
import { Thermometer, Activity, Battery, Wifi, Droplets } from 'lucide-react';

interface DashboardProps {
  fermenters: Fermenter[];
  onSelectFermenter: (id: string) => void;
}

const StatusBadge: React.FC<{ status: FermenterStatus }> = ({ status }) => {
  let colorClass = "bg-slate-700 text-slate-300";
  if (status === FermenterStatus.ACTIVE) colorClass = "bg-green-900/60 text-green-400 border border-green-800";
  if (status === FermenterStatus.COLD_CRASH) colorClass = "bg-blue-900/60 text-blue-400 border border-blue-800";
  if (status === FermenterStatus.IDLE) colorClass = "bg-slate-700/60 text-slate-400 border border-slate-600";

  return (
    <span className={`px-2 py-1 rounded-md text-xs font-medium uppercase tracking-wide ${colorClass}`}>
      {status}
    </span>
  );
};

export const Dashboard: React.FC<DashboardProps> = ({ fermenters, onSelectFermenter }) => {
  return (
    <div className="p-6 max-w-7xl mx-auto">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-white mb-2">Visão Geral da Cervejaria</h1>
        <p className="text-slate-400">Monitoramento em tempo real de {fermenters.length} fermentadores.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {fermenters.map((f) => (
          <div 
            key={f.id} 
            onClick={() => onSelectFermenter(f.id)}
            className="group bg-slate-800 border border-slate-700 hover:border-indigo-500 rounded-xl p-6 cursor-pointer transition-all hover:shadow-xl hover:shadow-indigo-500/10 hover:-translate-y-1 relative overflow-hidden"
          >
            {/* Top Bar: Name and Status */}
            <div className="flex justify-between items-start mb-4 relative z-10">
              <div>
                <h2 className="text-xl font-bold text-slate-100 group-hover:text-indigo-400 transition-colors">{f.name}</h2>
                <p className="text-sm text-slate-400">{f.beerName || 'Vazio'}</p>
              </div>
              <StatusBadge status={f.status} />
            </div>

            {/* Main Metrics */}
            <div className="grid grid-cols-2 gap-4 mb-6 relative z-10">
              <div className="flex flex-col">
                <span className="text-xs text-slate-500 uppercase flex items-center gap-1">
                  <Thermometer size={12} /> Temp Atual
                </span>
                <span className={`text-2xl font-mono font-bold ${Math.abs(f.currentDevice.temperature - f.targetTemp) < 0.5 ? 'text-green-400' : 'text-yellow-400'}`}>
                  {f.currentDevice.temperature.toFixed(1)}°C
                </span>
                <span className="text-xs text-slate-500">Alvo: {f.targetTemp}°C</span>
              </div>

              <div className="flex flex-col">
                 <span className="text-xs text-slate-500 uppercase flex items-center gap-1">
                  <Activity size={12} /> Gravidade
                </span>
                <span className="text-2xl font-mono font-bold text-purple-400">
                  {f.currentDevice.gravity.toFixed(3)}
                </span>
                <span className="text-xs text-slate-500">OG: {f.og.toFixed(3)}</span>
              </div>
            </div>

            {/* Footer: Device Stats */}
            <div className="flex items-center justify-between text-xs text-slate-500 border-t border-slate-700/50 pt-3 relative z-10">
              <div className="flex gap-3">
                 <span className="flex items-center gap-1" title="Bateria iSpindel">
                    <Battery size={14} className={f.currentDevice.battery < 3.5 ? 'text-red-400' : 'text-green-400'} /> 
