import { GoogleGenAI } from "@google/genai";
import { Fermenter } from "../types";

const initGenAI = () => {
  if (!process.env.API_KEY) {
    console.warn("API_KEY not found in environment variables.");
    return null;
  }
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const getBrewingInsights = async (fermenter: Fermenter): Promise<string> => {
  const ai = initGenAI();
  if (!ai) return "Erro: Chave de API não configurada. Por favor, verifique suas configurações.";

  // Downsample readings to avoid token limits, taking 1 reading every ~4 hours
  const filteredReadings = fermenter.readings.filter((_, i) => i % 4 === 0).map(r => ({
    t: r.timestamp,
    grav: r.gravity,
    beerT: r.beerTemp,
    fridgeT: r.fridgeTemp,
    tgt: r.targetTemp
  }));

  const prompt = `
    Aja como um Mestre Cervejeiro experiente e técnico. Analise os seguintes dados de fermentação para a cerveja "${fermenter.beerName}" (Estilo: ${fermenter.style}).

    Estado Atual: ${fermenter.status}
    OG: ${fermenter.og}
    Volume: ${fermenter.volume}L
    Target Temp (Setpoint): ${fermenter.targetTemp}°C

    Sensores Atuais:
    - Temp Mosto (Poço Termométrico): ${fermenter.currentDevice.temperature}°C
    - Temp Geladeira (Ambiente): ${fermenter.currentFridgeTemp}°C
    - Gravidade Atual: ${fermenter.currentDevice.gravity}

    Histórico recente (amostra temporal):
    ${JSON.stringify(filteredReadings.slice(-15))} 

    Por favor, forneça:
    1. Uma análise curta da saúde da fermentação (atenuação, e se o controle de temperatura da geladeira está eficiente em relação ao mosto).
    2. Identifique se há riscos (ex: inércia térmica excessiva, travamento de fermentação).
    3. Recomendação do próximo passo.

    Mantenha a resposta em Português do Brasil, tom profissional mas amigável. Use formatação Markdown.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Não foi possível gerar uma análise no momento.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Ocorreu um erro ao consultar o Mestre Cervejeiro IA.";
  }
};

