                <button 
                    onClick={() => {
                        setSelectedFermenterId(null);
                        setCurrentView('DASHBOARD');
                    }}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm font-medium transition-all ${currentView === 'DASHBOARD' && !selectedFermenterId ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
