const StatusBadge: React.FC<{ status: FermenterStatus }> = ({ status }) => {
  let dotColor = "bg-neutral-500";
  let textColor = "text-neutral-400";
  let containerClass = "bg-neutral-800/50 border-neutral-800";

  if (status === FermenterStatus.ACTIVE) {
    dotColor = "bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]";
    textColor = "text-green-400";
    containerClass = "bg-green-950/10 border-green-900/30";
  }
  if (status === FermenterStatus.COLD_CRASH) {
    dotColor = "bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.6)]";
    textColor = "text-blue-400";
    containerClass = "bg-blue-950/10 border-blue-900/30";
  }

  return (
    <div className={`flex items-center gap-2 px-3 py-1 rounded-full border ${containerClass} backdrop-blur-sm transition-all`}>
      <span className={`w-2 h-2 rounded-full ${dotColor} animate-pulse`}></span>
      <span className={`text-[10px] font-medium uppercase tracking-widest ${textColor}`}>
        {status}
      </span>
    </div>
  );
};

