                            onChange={(e) => setNewDeviceName(e.target.value)}
                            placeholder="Ex: Fermentador 03"
                            className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">IP / Serial</label>
                        <input 
                            type="text" 
                            value={newDeviceIp}
                            onChange={(e) => setNewDeviceIp(e.target.value)}
                            placeholder="Ex: 192.168.1.50 ou SERIAL_123"
                            className="w-full bg-black border border-neutral-800 text-white font-mono text-sm rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>

                    <button 
                        onClick={handleManualAdd}
                        disabled={!newDeviceName || !newDeviceIp}
                        className="w-full bg-white text-black font-medium py-3 rounded-xl mt-4 hover:bg-neutral-200 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        <Plus size={18} /> Adicionar Dispositivo
                    </button>
                </div>
             </div>
          </div>
      )}

      {/* MODAL 3: Scan Network */}
      {isScanModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
             <div className="bg-neutral-900 border border-neutral-800 p-6 rounded-2xl w-full max-w-md shadow-2xl scale-100 animate-in zoom-in-95 duration-200 relative">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-medium text-white">Procurar na Rede</h3>
                    <button onClick={() => {
                        setIsScanModalOpen(false);
                        setDeviceToAddFromScan(null);
                        setScannedDevices([]);
                    }} className="text-neutral-500 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                {/* Sub-view: Enter Name for Scanned Device */}
                {deviceToAddFromScan ? (
                    <div className="space-y-4 animate-in slide-in-from-right duration-300">
                        <div className="bg-neutral-800/50 p-4 rounded-xl border border-neutral-700 flex items-center justify-between mb-4">
                            <div>
                                <p className="text-sm text-white font-medium">{deviceToAddFromScan.type}</p>
                                <p className="text-xs text-neutral-500 font-mono">{deviceToAddFromScan.ip}</p>
                            </div>
                            <div className="text-xs text-green-500 font-mono">{deviceToAddFromScan.rssi} dBm</div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">Nomear Dispositivo</label>
                            <input 
                                type="text" 
                                value={newDeviceName}
                                onChange={(e) => setNewDeviceName(e.target.value)}
                                className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                                autoFocus
                            />
                        </div>

                        <div className="flex gap-2 mt-4">
                            <button 
                                onClick={() => setDeviceToAddFromScan(null)}
                                className="flex-1 bg-neutral-800 text-neutral-300 font-medium py-3 rounded-xl hover:bg-neutral-700 transition-colors"
                            >
                                Cancelar
                            </button>
                            <button 
                                onClick={handleSaveScanned}
                                disabled={!newDeviceName}
                                className="flex-1 bg-white text-black font-medium py-3 rounded-xl hover:bg-neutral-200 transition-colors disabled:opacity-50"
                            >
                                Salvar
                            </button>
                        </div>
                    </div>
                ) : (
                    /* Sub-view: List Scan Results */
                    <div className="min-h-[250px]">
                        {isScanning ? (
                            <div className="flex flex-col items-center justify-center h-64 space-y-4">
                                <div className="relative">
                                    <div className="absolute inset-0 bg-blue-500/20 blur-xl rounded-full animate-pulse"></div>
                                    <Loader2 size={48} className="text-blue-500 animate-spin relative z-10" />
                                </div>
                                <p className="text-neutral-400 text-sm animate-pulse">Escaneando rede local...</p>
                            </div>
                        ) : scannedDevices.length > 0 ? (
                            <div className="space-y-2">
                                <p className="text-xs text-neutral-500 mb-2 uppercase tracking-wide">Dispositivos Encontrados ({scannedDevices.length})</p>
                                {scannedDevices.map((device) => (
                                    <div key={device.ip} className="flex items-center justify-between bg-neutral-800/30 hover:bg-neutral-800 border border-neutral-800 hover:border-neutral-600 p-3 rounded-xl transition-all group">
                                        <div className="flex items-center gap-3">
                                            <div className="w-8 h-8 rounded-full bg-neutral-900 flex items-center justify-center text-neutral-500">
                                                <Smartphone size={16} />
                                            </div>
                                            <div>
                                                <p className="text-sm text-neutral-200 font-medium group-hover:text-white">{device.type}</p>
                                                <p className="text-[10px] text-neutral-600 font-mono">{device.ip}</p>
                                            </div>
                                        </div>
                                        <button 
                                            onClick={() => handleSelectScanned(device)}
                                            className="w-8 h-8 rounded-full bg-white text-black flex items-center justify-center hover:scale-110 transition-transform shadow-lg"
                                        >
                                            <Plus size={16} />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-64 text-center">
                                <Network size={48} className="text-neutral-800 mb-4" />
                                <p className="text-neutral-500 text-sm">Nenhum dispositivo encontrado.</p>
                                <button onClick={startScan} className="text-blue-500 text-xs mt-2 hover:underline">Tentar novamente</button>
                            </div>
                        )}
                    </div>
                )}
             </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Dashboard } from './components/Dashboard';
import { FermenterDetail } from './components/FermenterDetail';
import { Login } from './components/Login';
import { Register } from './components/Register';
import { FermentationHistory } from './components/FermentationHistory';
import { MOCK_FERMENTERS } from './services/mockData';
import { Fermenter, FermenterStatus, BeerStyle } from './types';
import { History, LayoutDashboard, LogOut, Server } from 'lucide-react';

type ViewState = 'DASHBOARD' | 'HISTORY';
type AuthState = 'LOGIN' | 'REGISTER';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [authView, setAuthView] = useState<AuthState>('LOGIN');
  const [currentView, setCurrentView] = useState<ViewState>('DASHBOARD');
  const [fermenters, setFermenters] = useState<Fermenter[]>(MOCK_FERMENTERS);
  const [selectedFermenterId, setSelectedFermenterId] = useState<string | null>(null);

  // Auto-refresh simulation (mocking real-time WebSocket)
  useEffect(() => {
    if (!isAuthenticated) return;

    const interval = setInterval(() => {
        setFermenters(prev => prev.map(f => ({
            ...f,
            currentDevice: {
                ...f.currentDevice,
                lastUpdate: new Date().toISOString()
            }
        })));
    }, 30000); // Update every 30s
    return () => clearInterval(interval);
  }, [isAuthenticated]);

  const handleUpdateFermenter = (id: string, updates: Partial<Fermenter>) => {
    setFermenters(prev => prev.map(f => 
        f.id === id ? { ...f, ...updates } : f
    ));
  };

  const handleAddFermenter = (newDevice: Partial<Fermenter>) => {
    const newFermenter: Fermenter = {
        id: Math.random().toString(36).substr(2, 9),
        name: newDevice.name || 'Novo Dispositivo',
        ipAddress: newDevice.ipAddress || '',
        status: FermenterStatus.IDLE,
        beerName: '',
        style: BeerStyle.LAGER, // Default
        startDate: '',
        og: 0,
        volume: 20,
        targetTemp: 20,
        readings: [],
        currentDevice: {
            gravity: 1.000,
            temperature: 20,
            battery: 0,
            angle: 0,
            rssi: 0,
            lastUpdate: ''
        },
        currentFridgeTemp: 20,
        profile: [],
        currentStepIndex: 0,
        isPaused: false,
        ...newDevice
    };
    setFermenters(prev => [...prev, newFermenter]);
  };

  const handleDeleteFermenter = (id: string) => {
    setFermenters(prev => prev.filter(f => f.id !== id));
    if (selectedFermenterId === id) {
        setSelectedFermenterId(null);
    }
  };

  const selectedFermenter = fermenters.find(f => f.id === selectedFermenterId);

  // Unauthenticated View
  if (!isAuthenticated) {
    if (authView === 'REGISTER') {
        return (
            <Register 
                onLogin={() => setIsAuthenticated(true)} 
                onSwitchToLogin={() => setAuthView('LOGIN')} 
            />
        );
    }
    return (
        <Login 
            onLogin={() => setIsAuthenticated(true)} 
            onSwitchToRegister={() => setAuthView('REGISTER')} 
        />
    );
  }

  // Authenticated Layout
  return (
    <div className="min-h-screen bg-black pb-10">
      {/* Navigation Bar */}
      <nav className="border-b border-neutral-800 bg-black/90 backdrop-blur sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div 
            className="flex items-center gap-3 cursor-pointer" 
            onClick={() => {
                setSelectedFermenterId(null);
                setCurrentView('DASHBOARD');
            }}
          >
            <div className="w-10 h-10 bg-gradient-to-br from-neutral-800 to-neutral-700 rounded-lg flex items-center justify-center border border-neutral-700 shadow-lg overflow-hidden">
                <img src="logo.svg" alt="BrewMaster Logo" className="w-full h-full object-cover" />
            </div>
            <span className="text-xl font-bold text-neutral-100 hidden sm:block">
                BrewMaster AI
            </span>
          </div>

          <div className="flex items-center gap-6">
             {/* Navigation Links */}
             <div className="flex bg-neutral-900/50 p-1 rounded-lg border border-neutral-800">
                <button 
                    onClick={() => {
                        setSelectedFermenterId(null);
                        setCurrentView('DASHBOARD');
                    }}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm font-medium transition-all ${currentView === 'DASHBOARD' && !selectedFermenterId ? 'bg-neutral-800 text-white border border-neutral-700 shadow-sm' : 'text-neutral-400 hover:text-white hover:bg-neutral-800'}`}
                >
                    <Server size={16} /> <span className="hidden sm:inline">Dispositivos</span>
                </button>
                <button 
                    onClick={() => {
                        setSelectedFermenterId(null);
                        setCurrentView('HISTORY');
                    }}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm font-medium transition-all ${currentView === 'HISTORY' ? 'bg-neutral-800 text-white border border-neutral-700 shadow-sm' : 'text-neutral-400 hover:text-white hover:bg-neutral-800'}`}
                >
                    <History size={16} /> <span className="hidden sm:inline">Logs</span>
                </button>
             </div>

             <div className="h-6 w-px bg-neutral-800 hidden sm:block"></div>

             <button 
                onClick={() => {
                    setIsAuthenticated(false);
                    setAuthView('LOGIN');
                }}
                className="text-neutral-500 hover:text-red-500 transition-colors"
                title="Sair"
             >
                <LogOut size={20} />
             </button>
          </div>
        </div>
      </nav>

      <main className="mt-6">
        {selectedFermenterId && selectedFermenter ? (
          <FermenterDetail 
            fermenter={selectedFermenter} 
            onBack={() => setSelectedFermenterId(null)}
            onUpdate={handleUpdateFermenter}
          />
        ) : currentView === 'HISTORY' ? (
          <FermentationHistory />
        ) : (
          <Dashboard 
            fermenters={fermenters} 
            onSelectFermenter={setSelectedFermenterId}
            onUpdateFermenter={handleUpdateFermenter}
            onAddFermenter={handleAddFermenter}
            onDeleteFermenter={handleDeleteFermenter}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Fermenter, FermenterStatus } from '../types';
import { Wifi, ArrowRight, Thermometer, Settings, X, Save, Network, Plus, Search, Loader2, Smartphone, Trash2, AlertTriangle } from 'lucide-react';

interface DashboardProps {
  fermenters: Fermenter[];
  onSelectFermenter: (id: string) => void;
  onUpdateFermenter: (id: string, updates: Partial<Fermenter>) => void;
  onAddFermenter: (fermenter: Partial<Fermenter>) => void;
  onDeleteFermenter: (id: string) => void;
}

interface ScannedDevice {
    ip: string;
    type: string;
    rssi: number;
}

export const Dashboard: React.FC<DashboardProps> = ({ fermenters, onSelectFermenter, onUpdateFermenter, onAddFermenter, onDeleteFermenter }) => {
  // Edit States
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');
  const [editIp, setEditIp] = useState('');

  // Delete State
  const [deletingId, setDeletingId] = useState<string | null>(null);

  // Add Manual States
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [newDeviceName, setNewDeviceName] = useState('');
  const [newDeviceIp, setNewDeviceIp] = useState('');

  // Scan States
  const [isScanModalOpen, setIsScanModalOpen] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scannedDevices, setScannedDevices] = useState<ScannedDevice[]>([]);
  const [deviceToAddFromScan, setDeviceToAddFromScan] = useState<ScannedDevice | null>(null);

  // Edit Handlers
  const handleEditClick = (e: React.MouseEvent, fermenter: Fermenter) => {
    e.stopPropagation(); // Prevent opening the detail view
    setEditingId(fermenter.id);
    setEditName(fermenter.name);
    setEditIp(fermenter.ipAddress || '');
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      setDeletingId(id);
  };

  const confirmDelete = () => {
      if (deletingId) {
          onDeleteFermenter(deletingId);
          setDeletingId(null);
      }
  };

  const handleSaveEdit = () => {
    if (editingId) {
        onUpdateFermenter(editingId, {
            name: editName,
            ipAddress: editIp
        });
        setEditingId(null);
    }
  };

  // Add Manual Handlers
  const handleManualAdd = () => {
      if (newDeviceName && newDeviceIp) {
          onAddFermenter({
              name: newDeviceName,
              ipAddress: newDeviceIp
          });
          setIsAddModalOpen(false);
          setNewDeviceName('');
          setNewDeviceIp('');
      }
  };

  // Scan Handlers
  const startScan = () => {
      setIsScanning(true);
      setScannedDevices([]);

      // Simulating Network Scan
      setTimeout(() => {
          setScannedDevices([
              { ip: '192.168.0.105', type: 'iSpindel v6', rssi: -55 },
              { ip: '192.168.0.112', type: 'ESP32 Controller', rssi: -72 },
              { ip: '192.168.0.124', type: 'Tiltbridge', rssi: -60 },
          ]);
          setIsScanning(false);
      }, 2500);
  };

  const handleSelectScanned = (device: ScannedDevice) => {
      setDeviceToAddFromScan(device);
      setNewDeviceName(`Novo ${device.type}`); // Default Name
  };

  const handleSaveScanned = () => {
      if (deviceToAddFromScan && newDeviceName) {
          onAddFermenter({
              name: newDeviceName,
              ipAddress: deviceToAddFromScan.ip
          });
          setIsScanModalOpen(false);
          setDeviceToAddFromScan(null);
          setScannedDevices([]);
      }
  };

  return (
    <div className="p-6 max-w-7xl mx-auto animate-in fade-in duration-500">
      <header className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
            <h1 className="text-4xl font-light tracking-tight text-white mb-2">Dispositivos</h1>
            <p className="text-neutral-500 font-light">Gerenciamento de equipamentos e conexões</p>
        </div>
        <div className="flex flex-col md:items-end gap-2">
            <div className="text-xs text-neutral-600 font-mono mb-1">
                {fermenters.length} UNIDADES CONECTADAS
            </div>
            <div className="flex items-center gap-2">
                <button 
                    onClick={() => {
                        setIsScanModalOpen(true);
                        startScan();
                    }}
                    className="flex items-center gap-2 px-4 py-2 bg-neutral-800 hover:bg-neutral-700 text-white rounded-lg text-xs font-bold uppercase tracking-wide transition-all border border-neutral-700"
                >
                    <Search size={14} /> Procurar
                </button>
                <button 
                    onClick={() => setIsAddModalOpen(true)}
                    className="flex items-center gap-2 px-4 py-2 bg-neutral-100 hover:bg-white text-black rounded-lg text-xs font-bold uppercase tracking-wide transition-all"
                >
                    <Plus size={14} /> Adicionar
                </button>
            </div>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {fermenters.map((f) => {
             const tempDiff = Math.abs(f.currentDevice.temperature - f.targetTemp);
             const isTempStable = tempDiff < 0.5;

             // Check connectivity (Offline if no update > 30 mins)
             const lastUpdate = new Date(f.currentDevice.lastUpdate).getTime();
             const now = new Date().getTime();
             const isOnline = !isNaN(lastUpdate) && (now - lastUpdate) < 30 * 60 * 1000;

             // Lógica inteligente de Status/Rampa
             let statusLabel = 'Inativo';
             let dotColor = "bg-neutral-500";
             let textColor = "text-neutral-400";
             let containerClass = "bg-neutral-800/50 border-neutral-800";

             if (f.status !== FermenterStatus.IDLE) {
                 // Se tem perfil e índice válido, usa o nome da rampa
                 if (f.profile && f.profile.length > 0 && f.currentStepIndex < f.profile.length) {
                     statusLabel = f.profile[f.currentStepIndex].name;
                 } else {
                     // Caso contrário (modo manual ou erro), usa o status genérico
                     statusLabel = f.status;
                 }

                 // Definição de Cores
                 if (f.status === FermenterStatus.COLD_CRASH) {
                    dotColor = "bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.6)]";
                    textColor = "text-blue-400";
                    containerClass = "bg-blue-950/10 border-blue-900/30";
                 } else {
                    dotColor = "bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]";
                    textColor = "text-green-400";
                    containerClass = "bg-green-950/10 border-green-900/30";
                 }
             }

             return (
              <div 
                key={f.id} 
                onClick={() => onSelectFermenter(f.id)}
                className="group relative bg-neutral-900/40 hover:bg-neutral-900/60 border border-neutral-800 hover:border-neutral-700 rounded-3xl p-8 cursor-pointer transition-all duration-300 hover:shadow-2xl hover:shadow-black/50 overflow-hidden"
              >
                {/* Header Section: Name & ID & Actions */}
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <span className="block text-xs font-bold text-neutral-400 uppercase tracking-widest">
                            {f.name}
                        </span>
                        <span className="block text-[10px] font-mono text-neutral-600 mt-1">
                            {f.ipAddress || 'ID_UNKNOWN'}
                        </span>
                    </div>

                    <div className="flex items-center gap-3">
                        {/* Online/Offline Dot */}
                        <div 
                            title={isOnline ? "Online" : "Offline"}
                            className={`w-2 h-2 rounded-full transition-all duration-500 ${isOnline ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)] animate-pulse' : 'bg-red-500/50 border border-red-900'}`} 
                        />

                        <div className="flex items-center bg-neutral-800/50 rounded-lg p-1 border border-neutral-700/50">
                            <button 
                                onClick={(e) => handleDeleteClick(e, f.id)}
                                className="text-neutral-500 hover:text-red-500 hover:bg-red-500/10 p-1.5 rounded-md transition-all"
                                title="Excluir Dispositivo"
                            >
                                <Trash2 size={14} />
                            </button>
                            <div className="w-px h-3 bg-neutral-700/50 mx-1"></div>
                            <button 
                                onClick={(e) => handleEditClick(e, f)}
                                className="text-neutral-500 hover:text-white hover:bg-neutral-700 p-1.5 rounded-md transition-all"
                                title="Configurações"
                            >
                                <Settings size={14} />
                            </button>
                        </div>
                    </div>
                </div>

                <div className="mb-8">
                    {/* Beer Name */}
                    <h2 className="text-2xl font-medium text-neutral-200 group-hover:text-white transition-colors truncate mb-3">
                        {f.beerName || 'Tanque Vazio'}
                    </h2>

                    {/* Smart Status Badge */}
                    <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full border ${containerClass} backdrop-blur-sm transition-all max-w-full`}>
                      <span className={`w-2 h-2 shrink-0 rounded-full ${dotColor} animate-pulse`}></span>
                      <span className={`text-[10px] font-medium uppercase tracking-widest ${textColor} truncate`}>
                        {statusLabel}
                      </span>
                    </div>
                </div>

                {/* Main Metrics - Clean & Large */}
                <div className="grid grid-cols-2 gap-8 mb-8">
                    {/* Temperature Column */}
                    <div className="relative">
                        <div className="flex items-start gap-1">
                            <span className={`text-5xl font-light tracking-tighter ${isTempStable ? 'text-white' : 'text-amber-500'}`}>
                                {f.currentDevice.temperature.toFixed(1)}
                            </span>
                            <span className="text-lg text-neutral-500 font-light mt-1">°C</span>
                        </div>
                        <div className="mt-2 flex items-center gap-2">
                             <div className="h-0.5 w-8 bg-neutral-700 rounded-full overflow-hidden">
                                <div className="h-full bg-neutral-400 w-1/2"></div>
                             </div>
                             <span className="text-xs text-neutral-500 font-mono">Alvo: {f.targetTemp.toFixed(1)}°</span>
                        </div>
                        {/* Sub-metric: Fridge */}
                        <div className="absolute -bottom-6 left-0 flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                             <Thermometer size={12} className="text-neutral-600" />
                             <span className="text-xs text-neutral-500">Geladeira: {f.currentFridgeTemp.toFixed(1)}°</span>
                        </div>
                    </div>

                    {/* Gravity Column */}
                    <div className="text-right">
                        <div className="flex items-start justify-end gap-1">
                             <span className="text-5xl font-light tracking-tighter text-purple-200">
                                {f.currentDevice.gravity.toFixed(3).substring(2)}
                             </span>
                             <span className="text-lg text-neutral-500 font-light mt-1">SG</span>
                        </div>
                        <span className="text-xs text-neutral-500 uppercase tracking-wider block mt-2">
                            OG: {f.og.toFixed(3)}
                        </span>
                    </div>
                </div>

                {/* Footer Info - Minimalist (No Battery) */}
                <div className="flex items-center justify-between pt-6 border-t border-neutral-800/50 mt-auto">
                    <div className="flex gap-4">
                        <div className="flex items-center gap-1.5 text-neutral-600 group-hover:text-neutral-400 transition-colors" title="Sinal Wifi">
                            <Wifi size={14} />
                            <span className="text-xs font-mono">{f.currentDevice.rssi}</span>
                        </div>
                    </div>

                    <div className="w-8 h-8 rounded-full bg-neutral-800 flex items-center justify-center text-neutral-500 group-hover:bg-white group-hover:text-black transition-all duration-300">
                        <ArrowRight size={14} />
                    </div>
                </div>

                {/* Background Decor */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-neutral-800/10 to-transparent rounded-bl-full pointer-events-none"></div>
              </div>
             );
        })}
      </div>

      {/* MODAL 1: Edit Existing Device */}
      {editingId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-neutral-900 border border-neutral-800 p-6 rounded-2xl w-full max-w-sm shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-medium text-white">Editar Dispositivo</h3>
                    <button onClick={() => setEditingId(null)} className="text-neutral-500 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                <div className="space-y-4">
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">Nome do Equipamento</label>
                        <input 
                            type="text" 
                            value={editName}
                            onChange={(e) => setEditName(e.target.value)}
                            className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">IP / Serial</label>
                        <input 
                            type="text" 
                            value={editIp}
                            onChange={(e) => setEditIp(e.target.value)}
                            className="w-full bg-black border border-neutral-800 text-white font-mono text-sm rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                            placeholder="192.168.x.x"
                        />
                    </div>

                    <button 
                        onClick={handleSaveEdit}
                        className="w-full bg-white text-black font-medium py-3 rounded-xl mt-4 hover:bg-neutral-200 transition-colors flex items-center justify-center gap-2"
                    >
                        <Save size={18} /> Salvar Alterações
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* MODAL 4: Delete Confirmation */}
      {deletingId && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
              <div className="bg-neutral-900 border border-red-900/50 p-6 rounded-2xl w-full max-w-sm shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                  <div className="flex flex-col items-center text-center">
                      <div className="w-12 h-12 bg-red-500/10 rounded-full flex items-center justify-center text-red-500 mb-4">
                          <AlertTriangle size={24} />
                      </div>
                      <h3 className="text-xl font-medium text-white mb-2">Excluir Dispositivo?</h3>
                      <p className="text-neutral-400 text-sm mb-6">
                          Essa ação não pode ser desfeita. Todos os dados e logs deste fermentador serão perdidos permanentemente.
                      </p>

                      <div className="flex w-full gap-3">
                          <button 
                              onClick={() => setDeletingId(null)}
                              className="flex-1 bg-neutral-800 hover:bg-neutral-700 text-white py-3 rounded-xl font-medium transition-colors"
                          >
                              Cancelar
                          </button>
                          <button 
                              onClick={confirmDelete}
                              className="flex-1 bg-red-600 hover:bg-red-500 text-white py-3 rounded-xl font-medium transition-colors shadow-[0_0_15px_rgba(220,38,38,0.4)]"
                          >
                              Sim, Excluir
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL 2: Add Manual Device */}
      {isAddModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
             <div className="bg-neutral-900 border border-neutral-800 p-6 rounded-2xl w-full max-w-sm shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-medium text-white">Adicionar Manualmente</h3>
                    <button onClick={() => setIsAddModalOpen(false)} className="text-neutral-500 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                <div className="space-y-4">
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">Nome do Equipamento</label>
                        <input 
                            type="text" 
                            value={newDeviceName}
                            onChange={(e) => setNewDeviceName(e.target.value)}
                            placeholder="Ex: Fermentador 03"
                            className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">IP / Serial</label>
                        <input 
                            type="text" 
                            value={newDeviceIp}
                            onChange={(e) => setNewDeviceIp(e.target.value)}
                            placeholder="Ex: 192.168.1.50 ou SERIAL_123"
                            className="w-full bg-black border border-neutral-800 text-white font-mono text-sm rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>

                    <button 
                        onClick={handleManualAdd}
                        disabled={!newDeviceName || !newDeviceIp}
                        className="w-full bg-white text-black font-medium py-3 rounded-xl mt-4 hover:bg-neutral-200 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        <Plus size={18} /> Adicionar Dispositivo
                    </button>
                </div>
             </div>
          </div>
      )}

      {/* MODAL 3: Scan Network */}
      {isScanModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
             <div className="bg-neutral-900 border border-neutral-800 p-6 rounded-2xl w-full max-w-md shadow-2xl scale-100 animate-in zoom-in-95 duration-200 relative">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-medium text-white">Procurar na Rede</h3>
                    <button onClick={() => {
                        setIsScanModalOpen(false);
                        setDeviceToAddFromScan(null);
                        setScannedDevices([]);
                    }} className="text-neutral-500 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                {/* Sub-view: Enter Name for Scanned Device */}
                {deviceToAddFromScan ? (
                    <div className="space-y-4 animate-in slide-in-from-right duration-300">
                        <div className="bg-neutral-800/50 p-4 rounded-xl border border-neutral-700 flex items-center justify-between mb-4">
                            <div>
                                <p className="text-sm text-white font-medium">{deviceToAddFromScan.type}</p>
                                <p className="text-xs text-neutral-500 font-mono">{deviceToAddFromScan.ip}</p>
                            </div>
                            <div className="text-xs text-green-500 font-mono">{deviceToAddFromScan.rssi} dBm</div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">Nomear Dispositivo</label>
                            <input 
                                type="text" 
                                value={newDeviceName}
                                onChange={(e) => setNewDeviceName(e.target.value)}
                                className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                                autoFocus
                            />
                        </div>

                        <div className="flex gap-2 mt-4">
                            <button 
                                onClick={() => setDeviceToAddFromScan(null)}
                                className="flex-1 bg-neutral-800 text-neutral-300 font-medium py-3 rounded-xl hover:bg-neutral-700 transition-colors"
                            >
                                Cancelar
                            </button>
                            <button 
                                onClick={handleSaveScanned}
                                disabled={!newDeviceName}
                                className="flex-1 bg-white text-black font-medium py-3 rounded-xl hover:bg-neutral-200 transition-colors disabled:opacity-50"
                            >
                                Salvar
                            </button>
                        </div>
                    </div>
                ) : (
                    /* Sub-view: List Scan Results */
                    <div className="min-h-[250px]">
                        {isScanning ? (
                            <div className="flex flex-col items-center justify-center h-64 space-y-4">
                                <div className="relative">
                                    <div className="absolute inset-0 bg-blue-500/20 blur-xl rounded-full animate-pulse"></div>
                                    <Loader2 size={48} className="text-blue-500 animate-spin relative z-10" />
                                </div>
                                <p className="text-neutral-400 text-sm animate-pulse">Escaneando rede local...</p>
                            </div>
                        ) : scannedDevices.length > 0 ? (
                            <div className="space-y-2">
                                <p className="text-xs text-neutral-500 mb-2 uppercase tracking-wide">Dispositivos Encontrados ({scannedDevices.length})</p>
                                {scannedDevices.map((device) => (
                                    <div key={device.ip} className="flex items-center justify-between bg-neutral-800/30 hover:bg-neutral-800 border border-neutral-800 hover:border-neutral-600 p-3 rounded-xl transition-all group">
                                        <div className="flex items-center gap-3">
                                            <div className="w-8 h-8 rounded-full bg-neutral-900 flex items-center justify-center text-neutral-500">
                                                <Smartphone size={16} />
                                            </div>
                                            <div>
                                                <p className="text-sm text-neutral-200 font-medium group-hover:text-white">{device.type}</p>
                                                <p className="text-[10px] text-neutral-600 font-mono">{device.ip}</p>
                                            </div>
                                        </div>
                                        <button 
                                            onClick={() => handleSelectScanned(device)}
                                            className="w-8 h-8 rounded-full bg-white text-black flex items-center justify-center hover:scale-110 transition-transform shadow-lg"
                                        >
                                            <Plus size={16} />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-64 text-center">
                                <Network size={48} className="text-neutral-800 mb-4" />
                                <p className="text-neutral-500 text-sm">Nenhum dispositivo encontrado.</p>
                                <button onClick={startScan} className="text-blue-500 text-xs mt-2 hover:underline">Tentar novamente</button>
                            </div>
                        )}
                    </div>
                )}
             </div>
          </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Fermenter, FermenterStatus } from '../types';
import { Wifi, ArrowRight, Thermometer, Settings, X, Save, Network, Plus, Search, Loader2, Smartphone, Trash2, AlertTriangle } from 'lucide-react';

interface DashboardProps {
  fermenters: Fermenter[];
  onSelectFermenter: (id: string) => void;
  onUpdateFermenter: (id: string, updates: Partial<Fermenter>) => void;
  onAddFermenter: (fermenter: Partial<Fermenter>) => void;
  onDeleteFermenter: (id: string) => void;
}

interface ScannedDevice {
    ip: string;
    type: string;
    rssi: number;
}

export const Dashboard: React.FC<DashboardProps> = ({ fermenters, onSelectFermenter, onUpdateFermenter, onAddFermenter, onDeleteFermenter }) => {
  // Edit States
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');
  const [editIp, setEditIp] = useState('');

  // Delete State
  const [deletingId, setDeletingId] = useState<string | null>(null);

  // Add Manual States
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [newDeviceName, setNewDeviceName] = useState('');
  const [newDeviceIp, setNewDeviceIp] = useState('');

  // Scan States
  const [isScanModalOpen, setIsScanModalOpen] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scannedDevices, setScannedDevices] = useState<ScannedDevice[]>([]);
  const [deviceToAddFromScan, setDeviceToAddFromScan] = useState<ScannedDevice | null>(null);

  // Edit Handlers
  const handleEditClick = (e: React.MouseEvent, fermenter: Fermenter) => {
    e.stopPropagation(); // Prevent opening the detail view
    setEditingId(fermenter.id);
    setEditName(fermenter.name);
    setEditIp(fermenter.ipAddress || '');
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      setDeletingId(id);
  };

  const confirmDelete = () => {
      if (deletingId) {
          onDeleteFermenter(deletingId);
          setDeletingId(null);
      }
  };

  const handleSaveEdit = () => {
    if (editingId) {
        onUpdateFermenter(editingId, {
            name: editName,
            ipAddress: editIp
        });
        setEditingId(null);
    }
  };

  // Add Manual Handlers
  const handleManualAdd = () => {
      if (newDeviceName && newDeviceIp) {
          onAddFermenter({
              name: newDeviceName,
              ipAddress: newDeviceIp
          });
          setIsAddModalOpen(false);
          setNewDeviceName('');
          setNewDeviceIp('');
      }
  };

  // Scan Handlers
  const startScan = () => {
      setIsScanning(true);
      setScannedDevices([]);

      // Simulating Network Scan
      setTimeout(() => {
          setScannedDevices([
              { ip: '192.168.0.105', type: 'iSpindel v6', rssi: -55 },
              { ip: '192.168.0.112', type: 'ESP32 Controller', rssi: -72 },
              { ip: '192.168.0.124', type: 'Tiltbridge', rssi: -60 },
          ]);
          setIsScanning(false);
      }, 2500);
  };

  const handleSelectScanned = (device: ScannedDevice) => {
      setDeviceToAddFromScan(device);
      setNewDeviceName(`Novo ${device.type}`); // Default Name
  };

  const handleSaveScanned = () => {
      if (deviceToAddFromScan && newDeviceName) {
          onAddFermenter({
              name: newDeviceName,
              ipAddress: deviceToAddFromScan.ip
          });
          setIsScanModalOpen(false);
          setDeviceToAddFromScan(null);
          setScannedDevices([]);
      }
  };

  return (
    <div className="p-6 max-w-7xl mx-auto animate-in fade-in duration-500">
      <header className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
            <h1 className="text-4xl font-light tracking-tight text-white mb-2">Dispositivos</h1>
            <p className="text-neutral-500 font-light">Gerenciamento de equipamentos e conexões</p>
        </div>
        <div className="flex flex-col md:items-end gap-2">
            <div className="text-xs text-neutral-600 font-mono mb-1">
                {fermenters.length} UNIDADES CONECTADAS
            </div>
            <div className="flex items-center gap-2">
                <button 
                    onClick={() => {
                        setIsScanModalOpen(true);
                        startScan();
                    }}
                    className="flex items-center gap-2 px-4 py-2 bg-neutral-800 hover:bg-neutral-700 text-white rounded-lg text-xs font-bold uppercase tracking-wide transition-all border border-neutral-700"
                >
                    <Search size={14} /> Procurar
                </button>
                <button 
                    onClick={() => setIsAddModalOpen(true)}
                    className="flex items-center gap-2 px-4 py-2 bg-neutral-100 hover:bg-white text-black rounded-lg text-xs font-bold uppercase tracking-wide transition-all"
                >
                    <Plus size={14} /> Adicionar
                </button>
            </div>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {fermenters.map((f) => {
             const tempDiff = Math.abs(f.currentDevice.temperature - f.targetTemp);
             const isTempStable = tempDiff < 0.5;

             // Check connectivity (Offline if no update > 30 mins)
             const lastUpdate = new Date(f.currentDevice.lastUpdate).getTime();
             const now = new Date().getTime();
             const isOnline = !isNaN(lastUpdate) && (now - lastUpdate) < 30 * 60 * 1000;

             // Lógica inteligente de Status/Rampa
             let statusLabel = 'Inativo';
             let dotColor = "bg-neutral-500";
             let textColor = "text-neutral-400";
             let containerClass = "bg-neutral-800/50 border-neutral-800";

             if (f.status !== FermenterStatus.IDLE) {
                 // Se tem perfil e índice válido, usa o nome da rampa
                 if (f.profile && f.profile.length > 0 && f.currentStepIndex < f.profile.length) {
                     statusLabel = f.profile[f.currentStepIndex].name;
                 } else {
                     // Caso contrário (modo manual ou erro), usa o status genérico
                     statusLabel = f.status;
                 }

                 // Definição de Cores
                 if (f.status === FermenterStatus.COLD_CRASH) {
                    dotColor = "bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.6)]";
                    textColor = "text-blue-400";
                    containerClass = "bg-blue-950/10 border-blue-900/30";
                 } else {
                    dotColor = "bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]";
                    textColor = "text-green-400";
                    containerClass = "bg-green-950/10 border-green-900/30";
                 }
             }

             return (
              <div 
                key={f.id} 
                onClick={() => onSelectFermenter(f.id)}
                className="group relative bg-neutral-900/40 hover:bg-neutral-900/60 border border-neutral-800 hover:border-neutral-700 rounded-3xl p-8 cursor-pointer transition-all duration-300 hover:shadow-2xl hover:shadow-black/50 overflow-hidden"
              >
                {/* Header Section: Name & ID & Actions */}
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <span className="block text-xs font-bold text-neutral-400 uppercase tracking-widest">
                            {f.name}
                        </span>
                        <span className="block text-[10px] font-mono text-neutral-600 mt-1">
                            {f.ipAddress || 'ID_UNKNOWN'}
                        </span>
                    </div>

                    <div className="flex items-center gap-3">
                        {/* Online/Offline Dot */}
                        <div 
                            title={isOnline ? "Online" : "Offline"}
                            className={`w-2 h-2 rounded-full transition-all duration-500 ${isOnline ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)] animate-pulse' : 'bg-red-500/50 border border-red-900'}`} 
                        />

                        <div className="flex items-center bg-neutral-800/50 rounded-lg p-1 border border-neutral-700/50">
                            <button 
                                onClick={(e) => handleDeleteClick(e, f.id)}
                                className="text-neutral-500 hover:text-red-500 hover:bg-red-500/10 p-1.5 rounded-md transition-all"
                                title="Excluir Dispositivo"
                            >
                                <Trash2 size={14} />
                            </button>
                            <div className="w-px h-3 bg-neutral-700/50 mx-1"></div>
                            <button 
                                onClick={(e) => handleEditClick(e, f)}
                                className="text-neutral-500 hover:text-white hover:bg-neutral-700 p-1.5 rounded-md transition-all"
                                title="Configurações"
                            >
                                <Settings size={14} />
                            </button>
                        </div>
                    </div>
                </div>

                <div className="mb-8">
                    {/* Beer Name */}
                    <h2 className="text-2xl font-medium text-neutral-200 group-hover:text-white transition-colors truncate mb-3">
                        {f.beerName || 'Tanque Vazio'}
                    </h2>

                    {/* Smart Status Badge */}
                    <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full border ${containerClass} backdrop-blur-sm transition-all max-w-full`}>
                      <span className={`w-2 h-2 shrink-0 rounded-full ${dotColor} animate-pulse`}></span>
                      <span className={`text-[10px] font-medium uppercase tracking-widest ${textColor} truncate`}>
                        {statusLabel}
                      </span>
                    </div>
                </div>

                {/* Main Metrics - Clean & Large */}
                <div className="grid grid-cols-2 gap-8 mb-8">
                    {/* Temperature Column */}
                    <div className="relative">
                        <div className="flex items-start gap-1">
                            <span className={`text-5xl font-light tracking-tighter ${isTempStable ? 'text-white' : 'text-amber-500'}`}>
                                {f.currentDevice.temperature.toFixed(1)}
                            </span>
                            <span className="text-lg text-neutral-500 font-light mt-1">°C</span>
                        </div>
                        <div className="mt-2 flex items-center gap-2">
                             <div className="h-0.5 w-8 bg-neutral-700 rounded-full overflow-hidden">
                                <div className="h-full bg-neutral-400 w-1/2"></div>
                             </div>
                             <span className="text-xs text-neutral-500 font-mono">Alvo: {f.targetTemp.toFixed(1)}°</span>
                        </div>
                        {/* Sub-metric: Fridge */}
                        <div className="absolute -bottom-6 left-0 flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                             <Thermometer size={12} className="text-neutral-600" />
                             <span className="text-xs text-neutral-500">Geladeira: {f.currentFridgeTemp.toFixed(1)}°</span>
                        </div>
                    </div>

                    {/* Gravity Column */}
                    <div className="text-right">
                        <div className="flex items-start justify-end gap-1">
                             <span className="text-4xl font-light tracking-tighter text-purple-200">
                                {f.currentDevice.gravity.toFixed(3)}
                             </span>
                             <span className="text-lg text-neutral-500 font-light mt-1">SG</span>
                        </div>
                        <span className="text-xs text-neutral-500 uppercase tracking-wider block mt-2">
                            OG: {f.og.toFixed(3)}
                        </span>
                    </div>
                </div>

                {/* Footer Info - Minimalist (No Battery) */}
                <div className="flex items-center justify-between pt-6 border-t border-neutral-800/50 mt-auto">
                    <div className="flex gap-4">
                        <div className="flex items-center gap-1.5 text-neutral-600 group-hover:text-neutral-400 transition-colors" title="Sinal Wifi">
                            <Wifi size={14} />
                            <span className="text-xs font-mono">{f.currentDevice.rssi}</span>
                        </div>
                    </div>

                    <div className="w-8 h-8 rounded-full bg-neutral-800 flex items-center justify-center text-neutral-500 group-hover:bg-white group-hover:text-black transition-all duration-300">
                        <ArrowRight size={14} />
                    </div>
                </div>

                {/* Background Decor */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-neutral-800/10 to-transparent rounded-bl-full pointer-events-none"></div>
              </div>
             );
        })}
      </div>

      {/* MODAL 1: Edit Existing Device */}
      {editingId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-neutral-900 border border-neutral-800 p-6 rounded-2xl w-full max-w-sm shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-medium text-white">Editar Dispositivo</h3>
                    <button onClick={() => setEditingId(null)} className="text-neutral-500 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                <div className="space-y-4">
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">Nome do Equipamento</label>
                        <input 
                            type="text" 
                            value={editName}
                            onChange={(e) => setEditName(e.target.value)}
                            className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">IP / Serial</label>
                        <input 
                            type="text" 
                            value={editIp}
                            onChange={(e) => setEditIp(e.target.value)}
                            className="w-full bg-black border border-neutral-800 text-white font-mono text-sm rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                            placeholder="192.168.x.x"
                        />
                    </div>

                    <button 
                        onClick={handleSaveEdit}
                        className="w-full bg-white text-black font-medium py-3 rounded-xl mt-4 hover:bg-neutral-200 transition-colors flex items-center justify-center gap-2"
                    >
                        <Save size={18} /> Salvar Alterações
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* MODAL 4: Delete Confirmation */}
      {deletingId && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
              <div className="bg-neutral-900 border border-red-900/50 p-6 rounded-2xl w-full max-w-sm shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                  <div className="flex flex-col items-center text-center">
                      <div className="w-12 h-12 bg-red-500/10 rounded-full flex items-center justify-center text-red-500 mb-4">
                          <AlertTriangle size={24} />
                      </div>
                      <h3 className="text-xl font-medium text-white mb-2">Excluir Dispositivo?</h3>
                      <p className="text-neutral-400 text-sm mb-6">
                          Essa ação não pode ser desfeita. Todos os dados e logs deste fermentador serão perdidos permanentemente.
                      </p>

                      <div className="flex w-full gap-3">
                          <button 
                              onClick={() => setDeletingId(null)}
                              className="flex-1 bg-neutral-800 hover:bg-neutral-700 text-white py-3 rounded-xl font-medium transition-colors"
                          >
                              Cancelar
                          </button>
                          <button 
                              onClick={confirmDelete}
                              className="flex-1 bg-red-600 hover:bg-red-500 text-white py-3 rounded-xl font-medium transition-colors shadow-[0_0_15px_rgba(220,38,38,0.4)]"
                          >
                              Sim, Excluir
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL 2: Add Manual Device */}
      {isAddModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
             <div className="bg-neutral-900 border border-neutral-800 p-6 rounded-2xl w-full max-w-sm shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-medium text-white">Adicionar Manualmente</h3>
                    <button onClick={() => setIsAddModalOpen(false)} className="text-neutral-500 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                <div className="space-y-4">
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">Nome do Equipamento</label>
                        <input 
                            type="text" 
                            value={newDeviceName}
                            onChange={(e) => setNewDeviceName(e.target.value)}
                            placeholder="Ex: Fermentador 03"
                            className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">IP / Serial</label>
                        <input 
                            type="text" 
                            value={newDeviceIp}
                            onChange={(e) => setNewDeviceIp(e.target.value)}
                            placeholder="Ex: 192.168.1.50 ou SERIAL_123"
                            className="w-full bg-black border border-neutral-800 text-white font-mono text-sm rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>

                    <button 
                        onClick={handleManualAdd}
                        disabled={!newDeviceName || !newDeviceIp}
                        className="w-full bg-white text-black font-medium py-3 rounded-xl mt-4 hover:bg-neutral-200 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        <Plus size={18} /> Adicionar Dispositivo
                    </button>
                </div>
             </div>
          </div>
      )}

      {/* MODAL 3: Scan Network */}
      {isScanModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
             <div className="bg-neutral-900 border border-neutral-800 p-6 rounded-2xl w-full max-w-md shadow-2xl scale-100 animate-in zoom-in-95 duration-200 relative">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-medium text-white">Procurar na Rede</h3>
                    <button onClick={() => {
                        setIsScanModalOpen(false);
                        setDeviceToAddFromScan(null);
                        setScannedDevices([]);
                    }} className="text-neutral-500 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                {/* Sub-view: Enter Name for Scanned Device */}
                {deviceToAddFromScan ? (
                    <div className="space-y-4 animate-in slide-in-from-right duration-300">
                        <div className="bg-neutral-800/50 p-4 rounded-xl border border-neutral-700 flex items-center justify-between mb-4">
                            <div>
                                <p className="text-sm text-white font-medium">{deviceToAddFromScan.type}</p>
                                <p className="text-xs text-neutral-500 font-mono">{deviceToAddFromScan.ip}</p>
                            </div>
                            <div className="text-xs text-green-500 font-mono">{deviceToAddFromScan.rssi} dBm</div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">Nomear Dispositivo</label>
                            <input 
                                type="text" 
                                value={newDeviceName}
                                onChange={(e) => setNewDeviceName(e.target.value)}
                                className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                                autoFocus
                            />
                        </div>

                        <div className="flex gap-2 mt-4">
                            <button 
                                onClick={() => setDeviceToAddFromScan(null)}
                                className="flex-1 bg-neutral-800 text-neutral-300 font-medium py-3 rounded-xl hover:bg-neutral-700 transition-colors"
                            >
                                Cancelar
                            </button>
                            <button 
                                onClick={handleSaveScanned}
                                disabled={!newDeviceName}
                                className="flex-1 bg-white text-black font-medium py-3 rounded-xl hover:bg-neutral-200 transition-colors disabled:opacity-50"
                            >
                                Salvar
                            </button>
                        </div>
                    </div>
                ) : (
                    /* Sub-view: List Scan Results */
                    <div className="min-h-[250px]">
                        {isScanning ? (
                            <div className="flex flex-col items-center justify-center h-64 space-y-4">
                                <div className="relative">
                                    <div className="absolute inset-0 bg-blue-500/20 blur-xl rounded-full animate-pulse"></div>
                                    <Loader2 size={48} className="text-blue-500 animate-spin relative z-10" />
                                </div>
                                <p className="text-neutral-400 text-sm animate-pulse">Escaneando rede local...</p>
                            </div>
                        ) : scannedDevices.length > 0 ? (
                            <div className="space-y-2">
                                <p className="text-xs text-neutral-500 mb-2 uppercase tracking-wide">Dispositivos Encontrados ({scannedDevices.length})</p>
                                {scannedDevices.map((device) => (
                                    <div key={device.ip} className="flex items-center justify-between bg-neutral-800/30 hover:bg-neutral-800 border border-neutral-800 hover:border-neutral-600 p-3 rounded-xl transition-all group">
                                        <div className="flex items-center gap-3">
                                            <div className="w-8 h-8 rounded-full bg-neutral-900 flex items-center justify-center text-neutral-500">
                                                <Smartphone size={16} />
                                            </div>
                                            <div>
                                                <p className="text-sm text-neutral-200 font-medium group-hover:text-white">{device.type}</p>
                                                <p className="text-[10px] text-neutral-600 font-mono">{device.ip}</p>
                                            </div>
                                        </div>
                                        <button 
                                            onClick={() => handleSelectScanned(device)}
                                            className="w-8 h-8 rounded-full bg-white text-black flex items-center justify-center hover:scale-110 transition-transform shadow-lg"
                                        >
                                            <Plus size={16} />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-64 text-center">
                                <Network size={48} className="text-neutral-800 mb-4" />
                                <p className="text-neutral-500 text-sm">Nenhum dispositivo encontrado.</p>
                                <button onClick={startScan} className="text-blue-500 text-xs mt-2 hover:underline">Tentar novamente</button>
                            </div>
                        )}
                    </div>
                )}
             </div>
          </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Fermenter, FermenterStatus, FermentationStep } from '../types';
import { ArrowLeft, ThermometerSnowflake, Flame, PauseCircle, PlayCircle, Save, Settings2, Snowflake, Battery, Wifi, Droplets } from 'lucide-react';
import { TemperatureChart } from './TemperatureChart';
import { GravityChart } from './GravityChart';
import { GeminiAdvisor } from './GeminiAdvisor';
import { FermentationProfile } from './FermentationProfile';

interface FermenterDetailProps {
  fermenter: Fermenter;
  onBack: () => void;
  onUpdate: (id: string, updates: Partial<Fermenter>) => void;
}

export const FermenterDetail: React.FC<FermenterDetailProps> = ({ fermenter, onBack, onUpdate }) => {
  const [targetTemp, setTargetTemp] = useState(fermenter.targetTemp);
  const [isEditing, setIsEditing] = useState(false);

  const handleSave = () => {
    onUpdate(fermenter.id, { targetTemp });
    setIsEditing(false);
  };

  const handleModeChange = (status: FermenterStatus) => {
    onUpdate(fermenter.id, { status });
  };

  const handleUpdateSteps = (newSteps: FermentationStep[]) => {
      onUpdate(fermenter.id, { profile: newSteps });
  };

  // Profile Control Handlers
  const handleTogglePause = () => {
    onUpdate(fermenter.id, { isPaused: !fermenter.isPaused });
  };

  const handleNextStep = () => {
    if (fermenter.profile && fermenter.currentStepIndex < fermenter.profile.length - 1) {
        onUpdate(fermenter.id, { currentStepIndex: fermenter.currentStepIndex + 1 });
    }
  };

  const handleFinishProfile = () => {
      // Moves status to IDLE and stops the profile
      onUpdate(fermenter.id, { 
          status: FermenterStatus.IDLE, 
          isPaused: false,
          currentStepIndex: 0 
      });
  };

  const abv = ((fermenter.og - fermenter.currentDevice.gravity) * 131.25).toFixed(1);

  return (
    <div className="p-6 md:p-8 max-w-7xl mx-auto animate-in fade-in duration-500">
      <button 
        onClick={onBack}
        className="flex items-center text-neutral-500 hover:text-white mb-8 transition-colors text-sm font-medium tracking-wide uppercase"
      >
        <ArrowLeft className="mr-2" size={16} /> Voltar
      </button>

      {/* Header Section Clean */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end mb-10 pb-6 border-b border-neutral-800/50">
        <div>
            <div className="flex items-center gap-3 mb-1">
                <span className={`w-2 h-2 rounded-full ${fermenter.currentDevice.lastUpdate ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-red-500'} animate-pulse`}></span>
                <span className="text-xs font-mono text-neutral-500 uppercase tracking-widest">{fermenter.name}</span>
            </div>
            <h1 className="text-5xl font-light text-white tracking-tight mb-2">{fermenter.beerName || 'Sem Nome'}</h1>
            <div className="flex items-center gap-4 text-sm text-neutral-500 font-light">
                <span className="bg-neutral-900 px-2 py-1 rounded text-neutral-400">{fermenter.style}</span>
                <span>Vol: {fermenter.volume}L</span>
                <span>Início: {fermenter.startDate ? new Date(fermenter.startDate).toLocaleDateString() : '--/--'}</span>
            </div>
        </div>

        {/* Status Actions */}
        <div className="flex gap-3 mt-4 md:mt-0">
             {fermenter.status === FermenterStatus.IDLE ? (
                <button 
                    onClick={() => handleModeChange(FermenterStatus.ACTIVE)}
                    className="bg-neutral-100 hover:bg-white text-black px-6 py-2 rounded-full font-medium text-sm transition-all"
                >
                    Iniciar Fermentação
                </button>
            ) : (
                <div className="flex gap-2">
                     <button 
                        onClick={() => handleModeChange(FermenterStatus.COLD_CRASH)}
                        className={`px-4 py-2 rounded-full text-xs font-medium uppercase tracking-wider transition-all border ${fermenter.status === FermenterStatus.COLD_CRASH ? 'bg-blue-500/10 text-blue-400 border-blue-500/50' : 'bg-neutral-900 text-neutral-500 border-neutral-800 hover:border-neutral-700'}`}
                     >
                        Cold Crash
                     </button>
                </div>
            )}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left Column: Charts */}
        <div className="lg:col-span-2 space-y-8">
            <TemperatureChart data={fermenter.readings} />
            <GravityChart data={fermenter.readings} />
            {/* Movido para cá para balancear a altura das colunas */}
            <GeminiAdvisor fermenter={fermenter} />
        </div>

        {/* Right Column: Metrics & Controls */}
        <div className="space-y-8">

            {/* Real-time Telemetry Card (Moved to Top) */}
            <div className="bg-neutral-900/30 rounded-3xl p-8 border border-neutral-800 backdrop-blur-sm relative overflow-hidden">
                <h3 className="text-neutral-500 text-xs font-bold uppercase tracking-widest mb-6">Telemetria em Tempo Real</h3>

                <div className="grid grid-cols-2 gap-8 mb-8">
                    <div>
                        <span className="block text-neutral-600 text-xs mb-1">Temperatura (Mosto)</span>
                        <div className="flex items-start gap-1">
                            <span className="text-4xl font-light text-amber-500 tracking-tighter">
                                {fermenter.currentDevice.temperature.toFixed(1)}
                            </span>
                            <span className="text-sm text-neutral-500 mt-1">°C</span>
                        </div>
                    </div>
                    <div>
                        <span className="block text-neutral-600 text-xs mb-1">Gravidade (SG)</span>
                        <div className="flex items-start gap-1">
                            <span className="text-4xl font-light text-purple-400 tracking-tighter">
                                {fermenter.currentDevice.gravity.toFixed(3)}
                            </span>
                            <span className="text-sm text-neutral-500 mt-1">SG</span>
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-3 gap-4 pt-6 border-t border-neutral-800/50">
                    <div className="text-center">
                        <Battery size={16} className="text-neutral-600 mx-auto mb-2" />
                        <span className="block text-sm font-mono text-neutral-300">{fermenter.currentDevice.battery}V</span>
                    </div>
                    <div className="text-center border-l border-neutral-800/50">
                        <Droplets size={16} className="text-neutral-600 mx-auto mb-2" />
                        <span className="block text-sm font-mono text-neutral-300">{fermenter.currentDevice.angle.toFixed(0)}°</span>
                    </div>
                    <div className="text-center border-l border-neutral-800/50">
                        <span className="block text-[10px] font-bold text-neutral-600 uppercase mb-2">ABV EST.</span>
                        <span className="block text-sm font-mono text-green-500">{abv}%</span>
                    </div>
                </div>
            </div>

            {/* Novo Componente de Rampas */}
            <FermentationProfile 
                steps={fermenter.profile || []} 
                currentStepIndex={fermenter.currentStepIndex || 0}
                isPaused={fermenter.isPaused || false}
                onUpdateSteps={handleUpdateSteps}
                onTogglePause={handleTogglePause}
                onNextStep={handleNextStep}
                onFinishProfile={handleFinishProfile}
            />

            {/* Control Card - Manual Override (Moved to Bottom) */}
            <div className="bg-neutral-900/30 rounded-3xl p-6 border border-neutral-800 backdrop-blur-sm">
                <div className="flex justify-between items-center mb-6">
                    <span className="text-neutral-500 text-xs font-bold uppercase tracking-widest">Controle Manual</span>
                    <button onClick={() => isEditing ? handleSave() : setIsEditing(true)} className="text-neutral-400 hover:text-white transition-colors">
                        {isEditing ? <Save size={18} /> : <Settings2 size={18} />}
                    </button>
                </div>

                <div className="flex items-baseline justify-between">
                     <div className="flex flex-col">
                        <span className="text-neutral-600 text-sm mb-1">Set-point Atual</span>
                        <div className="flex items-center gap-1">
                             {isEditing ? (
                                <input 
                                    type="number" 
                                    value={targetTemp}
                                    onChange={(e) => setTargetTemp(parseFloat(e.target.value))}
                                    step="0.1"
                                    className="bg-transparent border-b border-white text-4xl font-light text-white w-24 outline-none font-mono"
                                    autoFocus
                                />
                             ) : (
                                <span className="text-4xl font-light text-white font-mono">{fermenter.targetTemp.toFixed(1)}</span>
                             )}
                             <span className="text-lg text-neutral-500">°C</span>
                        </div>
                     </div>

                     <div className="flex flex-col items-end">
                        <span className="text-neutral-600 text-sm mb-1">Geladeira</span>
                        <div className="flex items-center gap-2">
                             <Snowflake size={14} className="text-blue-500/70" />
                             <span className="text-2xl font-light text-neutral-300 font-mono">{fermenter.currentFridgeTemp.toFixed(1)}°</span>
                        </div>
                     </div>
                </div>
            </div>

        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Fermenter, FermenterStatus } from '../types';
import { Wifi, ArrowRight, Thermometer, Settings, X, Save, Network, Plus, Search, Loader2, Smartphone, Trash2, AlertTriangle } from 'lucide-react';

interface DashboardProps {
  fermenters: Fermenter[];
  onSelectFermenter: (id: string) => void;
  onUpdateFermenter: (id: string, updates: Partial<Fermenter>) => void;
  onAddFermenter: (fermenter: Partial<Fermenter>) => void;
  onDeleteFermenter: (id: string) => void;
}

interface ScannedDevice {
    ip: string;
    type: string;
    rssi: number;
}

export const Dashboard: React.FC<DashboardProps> = ({ fermenters, onSelectFermenter, onUpdateFermenter, onAddFermenter, onDeleteFermenter }) => {
  // Edit States
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');
  const [editIp, setEditIp] = useState('');

  // Delete State
  const [deletingId, setDeletingId] = useState<string | null>(null);

  // Add Manual States
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [newDeviceName, setNewDeviceName] = useState('');
  const [newDeviceIp, setNewDeviceIp] = useState('');

  // Scan States
  const [isScanModalOpen, setIsScanModalOpen] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scannedDevices, setScannedDevices] = useState<ScannedDevice[]>([]);
  const [deviceToAddFromScan, setDeviceToAddFromScan] = useState<ScannedDevice | null>(null);

  // Edit Handlers
  const handleEditClick = (e: React.MouseEvent, fermenter: Fermenter) => {
    e.stopPropagation(); // Prevent opening the detail view
    setEditingId(fermenter.id);
    setEditName(fermenter.name);
    setEditIp(fermenter.ipAddress || '');
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      setDeletingId(id);
  };

  const confirmDelete = () => {
      if (deletingId) {
          onDeleteFermenter(deletingId);
          setDeletingId(null);
      }
  };

  const handleSaveEdit = () => {
    if (editingId) {
        onUpdateFermenter(editingId, {
            name: editName,
            ipAddress: editIp
        });
        setEditingId(null);
    }
  };

  // Add Manual Handlers
  const handleManualAdd = () => {
      if (newDeviceName && newDeviceIp) {
          onAddFermenter({
              name: newDeviceName,
              ipAddress: newDeviceIp
          });
          setIsAddModalOpen(false);
          setNewDeviceName('');
          setNewDeviceIp('');
      }
  };

  // Scan Handlers
  const startScan = () => {
      setIsScanning(true);
      setScannedDevices([]);

      // Simulating Network Scan
      setTimeout(() => {
          setScannedDevices([
              { ip: '192.168.0.105', type: 'iSpindel v6', rssi: -55 },
              { ip: '192.168.0.112', type: 'ESP32 Controller', rssi: -72 },
              { ip: '192.168.0.124', type: 'Tiltbridge', rssi: -60 },
          ]);
          setIsScanning(false);
      }, 2500);
  };

  const handleSelectScanned = (device: ScannedDevice) => {
      setDeviceToAddFromScan(device);
      setNewDeviceName(`Novo ${device.type}`); // Default Name
  };

  const handleSaveScanned = () => {
      if (deviceToAddFromScan && newDeviceName) {
          onAddFermenter({
              name: newDeviceName,
              ipAddress: deviceToAddFromScan.ip
          });
          setIsScanModalOpen(false);
          setDeviceToAddFromScan(null);
          setScannedDevices([]);
      }
  };

  return (
    <div className="p-6 max-w-7xl mx-auto animate-in fade-in duration-500">
      <header className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
            <h1 className="text-4xl font-light tracking-tight text-white mb-2">Dispositivos</h1>
            <p className="text-neutral-500 font-light">Gerenciamento de equipamentos e conexões</p>
        </div>
        <div className="flex flex-col md:items-end gap-2">
            <div className="text-xs text-neutral-600 font-mono mb-1">
                {fermenters.length} UNIDADES CONECTADAS
            </div>
            <div className="flex items-center gap-2">
                <button 
                    onClick={() => {
                        setIsScanModalOpen(true);
                        startScan();
                    }}
                    className="flex items-center gap-2 px-4 py-2 bg-neutral-800 hover:bg-neutral-700 text-white rounded-lg text-xs font-bold uppercase tracking-wide transition-all border border-neutral-700"
                >
                    <Search size={14} /> Procurar
                </button>
                <button 
                    onClick={() => setIsAddModalOpen(true)}
                    className="flex items-center gap-2 px-4 py-2 bg-neutral-100 hover:bg-white text-black rounded-lg text-xs font-bold uppercase tracking-wide transition-all"
                >
                    <Plus size={14} /> Adicionar
                </button>
            </div>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {fermenters.map((f) => {
             const tempDiff = Math.abs(f.currentDevice.temperature - f.targetTemp);
             const isTempStable = tempDiff < 0.5;

             // Check connectivity (Offline if no update > 30 mins)
             const lastUpdate = new Date(f.currentDevice.lastUpdate).getTime();
             const now = new Date().getTime();
             const isOnline = !isNaN(lastUpdate) && (now - lastUpdate) < 30 * 60 * 1000;

             // Lógica inteligente de Status/Rampa
             let statusLabel = 'Inativo';
             let dotColor = "bg-neutral-500";
             let textColor = "text-neutral-400";
             let containerClass = "bg-neutral-800/50 border-neutral-800";

             if (f.status !== FermenterStatus.IDLE) {
                 // Se tem perfil e índice válido, usa o nome da rampa
                 if (f.profile && f.profile.length > 0 && f.currentStepIndex < f.profile.length) {
                     statusLabel = f.profile[f.currentStepIndex].name;
                 } else {
                     // Caso contrário (modo manual ou erro), usa o status genérico
                     statusLabel = f.status;
                 }

                 // Definição de Cores
                 if (f.status === FermenterStatus.COLD_CRASH) {
                    dotColor = "bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.6)]";
                    textColor = "text-blue-400";
                    containerClass = "bg-blue-950/10 border-blue-900/30";
                 } else {
                    dotColor = "bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]";
                    textColor = "text-green-400";
                    containerClass = "bg-green-950/10 border-green-900/30";
                 }
             }

             return (
              <div 
                key={f.id} 
                onClick={() => onSelectFermenter(f.id)}
                className="group relative bg-neutral-900/40 hover:bg-neutral-900/60 border border-neutral-800 hover:border-neutral-700 rounded-3xl p-8 cursor-pointer transition-all duration-300 hover:shadow-2xl hover:shadow-black/50 overflow-hidden"
              >
                {/* Header Section: Name & ID & Actions */}
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <span className="block text-xs font-bold text-neutral-400 uppercase tracking-widest">
                            {f.name}
                        </span>
                        <span className="block text-[10px] font-mono text-neutral-600 mt-1">
                            {f.ipAddress || 'ID_UNKNOWN'}
                        </span>
                    </div>

                    <div className="flex items-center gap-3">
                        {/* Online/Offline Dot */}
                        <div 
                            title={isOnline ? "Online" : "Offline"}
                            className={`w-2 h-2 rounded-full transition-all duration-500 ${isOnline ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)] animate-pulse' : 'bg-red-500/50 border border-red-900'}`} 
                        />

                        <div className="flex items-center bg-neutral-800/50 rounded-lg p-1 border border-neutral-700/50">
                            <button 
                                onClick={(e) => handleDeleteClick(e, f.id)}
                                className="text-neutral-500 hover:text-red-500 hover:bg-red-500/10 p-1.5 rounded-md transition-all"
                                title="Excluir Dispositivo"
                            >
                                <Trash2 size={14} />
                            </button>
                            <div className="w-px h-3 bg-neutral-700/50 mx-1"></div>
                            <button 
                                onClick={(e) => handleEditClick(e, f)}
                                className="text-neutral-500 hover:text-white hover:bg-neutral-700 p-1.5 rounded-md transition-all"
                                title="Configurações"
                            >
                                <Settings size={14} />
                            </button>
                        </div>
                    </div>
                </div>

                <div className="mb-8">
                    {/* Beer Name */}
                    <h2 className="text-2xl font-bold text-white group-hover:text-white transition-colors truncate mb-3 tracking-tight">
                        {f.beerName || 'Tanque Vazio'}
                    </h2>

                    {/* Smart Status Badge */}
                    <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full border ${containerClass} backdrop-blur-sm transition-all max-w-full`}>
                      <span className={`w-2 h-2 shrink-0 rounded-full ${dotColor} animate-pulse`}></span>
                      <span className={`text-[10px] font-medium uppercase tracking-widest ${textColor} truncate`}>
                        {statusLabel}
                      </span>
                    </div>
                </div>

                {/* Main Metrics - Clean & Large */}
                <div className="grid grid-cols-2 gap-8 mb-8">
                    {/* Temperature Column */}
                    <div className="relative">
                        <div className="flex items-start gap-1">
                            <span className={`text-5xl font-light tracking-tighter ${isTempStable ? 'text-white' : 'text-amber-500'}`}>
                                {f.currentDevice.temperature.toFixed(1)}
                            </span>
                            <span className="text-lg text-neutral-500 font-light mt-1">°C</span>
                        </div>
                        <div className="mt-2 flex items-center gap-2">
                             <div className="h-0.5 w-8 bg-neutral-700 rounded-full overflow-hidden">
                                <div className="h-full bg-neutral-400 w-1/2"></div>
                             </div>
                             <span className="text-xs text-neutral-500 font-mono">Alvo: {f.targetTemp.toFixed(1)}°</span>
                        </div>
                        {/* Sub-metric: Fridge */}
                        <div className="absolute -bottom-6 left-0 flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                             <Thermometer size={12} className="text-neutral-600" />
                             <span className="text-xs text-neutral-500">Geladeira: {f.currentFridgeTemp.toFixed(1)}°</span>
                        </div>
                    </div>

                    {/* Gravity Column */}
                    <div className="text-right">
                        <div className="flex items-start justify-end gap-1">
                             <span className="text-4xl font-light tracking-tighter text-purple-200">
                                {f.currentDevice.gravity.toFixed(3)}
                             </span>
                             <span className="text-lg text-neutral-500 font-light mt-1">SG</span>
                        </div>
                        <span className="text-xs text-neutral-500 uppercase tracking-wider block mt-2">
                            OG: {f.og.toFixed(3)}
                        </span>
                    </div>
                </div>

                {/* Footer Info - Minimalist (No Battery) */}
                <div className="flex items-center justify-between pt-6 border-t border-neutral-800/50 mt-auto">
                    <div className="flex gap-4">
                        <div className="flex items-center gap-1.5 text-neutral-600 group-hover:text-neutral-400 transition-colors" title="Sinal Wifi">
                            <Wifi size={14} />
                            <span className="text-xs font-mono">{f.currentDevice.rssi}</span>
                        </div>
                    </div>

                    <div className="w-8 h-8 rounded-full bg-neutral-800 flex items-center justify-center text-neutral-500 group-hover:bg-white group-hover:text-black transition-all duration-300">
                        <ArrowRight size={14} />
                    </div>
                </div>

                {/* Background Decor */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-neutral-800/10 to-transparent rounded-bl-full pointer-events-none"></div>
              </div>
             );
        })}
      </div>

      {/* MODAL 1: Edit Existing Device */}
      {editingId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-neutral-900 border border-neutral-800 p-6 rounded-2xl w-full max-w-sm shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-medium text-white">Editar Dispositivo</h3>
                    <button onClick={() => setEditingId(null)} className="text-neutral-500 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                <div className="space-y-4">
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">Nome do Equipamento</label>
                        <input 
                            type="text" 
                            value={editName}
                            onChange={(e) => setEditName(e.target.value)}
                            className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">IP / Serial</label>
                        <input 
                            type="text" 
                            value={editIp}
                            onChange={(e) => setEditIp(e.target.value)}
                            className="w-full bg-black border border-neutral-800 text-white font-mono text-sm rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                            placeholder="192.168.x.x"
                        />
                    </div>

                    <button 
                        onClick={handleSaveEdit}
                        className="w-full bg-white text-black font-medium py-3 rounded-xl mt-4 hover:bg-neutral-200 transition-colors flex items-center justify-center gap-2"
                    >
                        <Save size={18} /> Salvar Alterações
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* MODAL 4: Delete Confirmation */}
      {deletingId && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
              <div className="bg-neutral-900 border border-red-900/50 p-6 rounded-2xl w-full max-w-sm shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                  <div className="flex flex-col items-center text-center">
                      <div className="w-12 h-12 bg-red-500/10 rounded-full flex items-center justify-center text-red-500 mb-4">
                          <AlertTriangle size={24} />
                      </div>
                      <h3 className="text-xl font-medium text-white mb-2">Excluir Dispositivo?</h3>
                      <p className="text-neutral-400 text-sm mb-6">
                          Essa ação não pode ser desfeita. Todos os dados e logs deste fermentador serão perdidos permanentemente.
                      </p>

                      <div className="flex w-full gap-3">
                          <button 
                              onClick={() => setDeletingId(null)}
                              className="flex-1 bg-neutral-800 hover:bg-neutral-700 text-white py-3 rounded-xl font-medium transition-colors"
                          >
                              Cancelar
                          </button>
                          <button 
                              onClick={confirmDelete}
                              className="flex-1 bg-red-600 hover:bg-red-500 text-white py-3 rounded-xl font-medium transition-colors shadow-[0_0_15px_rgba(220,38,38,0.4)]"
                          >
                              Sim, Excluir
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL 2: Add Manual Device */}
      {isAddModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
             <div className="bg-neutral-900 border border-neutral-800 p-6 rounded-2xl w-full max-w-sm shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-medium text-white">Adicionar Manualmente</h3>
                    <button onClick={() => setIsAddModalOpen(false)} className="text-neutral-500 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                <div className="space-y-4">
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">Nome do Equipamento</label>
                        <input 
                            type="text" 
                            value={newDeviceName}
                            onChange={(e) => setNewDeviceName(e.target.value)}
                            placeholder="Ex: Fermentador 03"
                            className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">IP / Serial</label>
                        <input 
                            type="text" 
                            value={newDeviceIp}
                            onChange={(e) => setNewDeviceIp(e.target.value)}
                            placeholder="Ex: 192.168.1.50 ou SERIAL_123"
                            className="w-full bg-black border border-neutral-800 text-white font-mono text-sm rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>

                    <button 
                        onClick={handleManualAdd}
                        disabled={!newDeviceName || !newDeviceIp}
                        className="w-full bg-white text-black font-medium py-3 rounded-xl mt-4 hover:bg-neutral-200 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        <Plus size={18} /> Adicionar Dispositivo
                    </button>
                </div>
             </div>
          </div>
      )}

      {/* MODAL 3: Scan Network */}
      {isScanModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
             <div className="bg-neutral-900 border border-neutral-800 p-6 rounded-2xl w-full max-w-md shadow-2xl scale-100 animate-in zoom-in-95 duration-200 relative">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-medium text-white">Procurar na Rede</h3>
                    <button onClick={() => {
                        setIsScanModalOpen(false);
                        setDeviceToAddFromScan(null);
                        setScannedDevices([]);
                    }} className="text-neutral-500 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                {/* Sub-view: Enter Name for Scanned Device */}
                {deviceToAddFromScan ? (
                    <div className="space-y-4 animate-in slide-in-from-right duration-300">
                        <div className="bg-neutral-800/50 p-4 rounded-xl border border-neutral-700 flex items-center justify-between mb-4">
                            <div>
                                <p className="text-sm text-white font-medium">{deviceToAddFromScan.type}</p>
                                <p className="text-xs text-neutral-500 font-mono">{deviceToAddFromScan.ip}</p>
                            </div>
                            <div className="text-xs text-green-500 font-mono">{deviceToAddFromScan.rssi} dBm</div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">Nomear Dispositivo</label>
                            <input 
                                type="text" 
                                value={newDeviceName}
                                onChange={(e) => setNewDeviceName(e.target.value)}
                                className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                                autoFocus
                            />
                        </div>

                        <div className="flex gap-2 mt-4">
                            <button 
                                onClick={() => setDeviceToAddFromScan(null)}
                                className="flex-1 bg-neutral-800 text-neutral-300 font-medium py-3 rounded-xl hover:bg-neutral-700 transition-colors"
                            >
                                Cancelar
                            </button>
                            <button 
                                onClick={handleSaveScanned}
                                disabled={!newDeviceName}
                                className="flex-1 bg-white text-black font-medium py-3 rounded-xl hover:bg-neutral-200 transition-colors disabled:opacity-50"
                            >
                                Salvar
                            </button>
                        </div>
                    </div>
                ) : (
                    /* Sub-view: List Scan Results */
                    <div className="min-h-[250px]">
                        {isScanning ? (
                            <div className="flex flex-col items-center justify-center h-64 space-y-4">
                                <div className="relative">
                                    <div className="absolute inset-0 bg-blue-500/20 blur-xl rounded-full animate-pulse"></div>
                                    <Loader2 size={48} className="text-blue-500 animate-spin relative z-10" />
                                </div>
                                <p className="text-neutral-400 text-sm animate-pulse">Escaneando rede local...</p>
                            </div>
                        ) : scannedDevices.length > 0 ? (
                            <div className="space-y-2">
                                <p className="text-xs text-neutral-500 mb-2 uppercase tracking-wide">Dispositivos Encontrados ({scannedDevices.length})</p>
                                {scannedDevices.map((device) => (
                                    <div key={device.ip} className="flex items-center justify-between bg-neutral-800/30 hover:bg-neutral-800 border border-neutral-800 hover:border-neutral-600 p-3 rounded-xl transition-all group">
                                        <div className="flex items-center gap-3">
                                            <div className="w-8 h-8 rounded-full bg-neutral-900 flex items-center justify-center text-neutral-500">
                                                <Smartphone size={16} />
                                            </div>
                                            <div>
                                                <p className="text-sm text-neutral-200 font-medium group-hover:text-white">{device.type}</p>
                                                <p className="text-[10px] text-neutral-600 font-mono">{device.ip}</p>
                                            </div>
                                        </div>
                                        <button 
                                            onClick={() => handleSelectScanned(device)}
                                            className="w-8 h-8 rounded-full bg-white text-black flex items-center justify-center hover:scale-110 transition-transform shadow-lg"
                                        >
                                            <Plus size={16} />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-64 text-center">
                                <Network size={48} className="text-neutral-800 mb-4" />
                                <p className="text-neutral-500 text-sm">Nenhum dispositivo encontrado.</p>
                                <button onClick={startScan} className="text-blue-500 text-xs mt-2 hover:underline">Tentar novamente</button>
                            </div>
                        )}
                    </div>
                )}
             </div>
          </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Fermenter, FermenterStatus } from '../types';
import { Wifi, ArrowRight, Thermometer, Settings, X, Save, Network, Plus, Search, Loader2, Smartphone, Trash2, AlertTriangle } from 'lucide-react';

interface DashboardProps {
  fermenters: Fermenter[];
  onSelectFermenter: (id: string) => void;
  onUpdateFermenter: (id: string, updates: Partial<Fermenter>) => void;
  onAddFermenter: (fermenter: Partial<Fermenter>) => void;
  onDeleteFermenter: (id: string) => void;
}

interface ScannedDevice {
    ip: string;
    type: string;
    rssi: number;
}

export const Dashboard: React.FC<DashboardProps> = ({ fermenters, onSelectFermenter, onUpdateFermenter, onAddFermenter, onDeleteFermenter }) => {
  // Edit States
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');
  const [editIp, setEditIp] = useState('');

  // Delete State
  const [deletingId, setDeletingId] = useState<string | null>(null);

  // Add Manual States
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [newDeviceName, setNewDeviceName] = useState('');
  const [newDeviceIp, setNewDeviceIp] = useState('');

  // Scan States
  const [isScanModalOpen, setIsScanModalOpen] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scannedDevices, setScannedDevices] = useState<ScannedDevice[]>([]);
  const [deviceToAddFromScan, setDeviceToAddFromScan] = useState<ScannedDevice | null>(null);

  // Edit Handlers
  const handleEditClick = (e: React.MouseEvent, fermenter: Fermenter) => {
    e.stopPropagation(); // Prevent opening the detail view
    setEditingId(fermenter.id);
    setEditName(fermenter.name);
    setEditIp(fermenter.ipAddress || '');
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      setDeletingId(id);
  };

  const confirmDelete = () => {
      if (deletingId) {
          onDeleteFermenter(deletingId);
          setDeletingId(null);
      }
  };

  const handleSaveEdit = () => {
    if (editingId) {
        onUpdateFermenter(editingId, {
            name: editName,
            ipAddress: editIp
        });
        setEditingId(null);
    }
  };

  // Add Manual Handlers
  const handleManualAdd = () => {
      if (newDeviceName && newDeviceIp) {
          onAddFermenter({
              name: newDeviceName,
              ipAddress: newDeviceIp
          });
          setIsAddModalOpen(false);
          setNewDeviceName('');
          setNewDeviceIp('');
      }
  };

  // Scan Handlers
  const startScan = () => {
      setIsScanning(true);
      setScannedDevices([]);

      // Simulating Network Scan
      setTimeout(() => {
          setScannedDevices([
              { ip: '192.168.0.105', type: 'iSpindel v6', rssi: -55 },
              { ip: '192.168.0.112', type: 'ESP32 Controller', rssi: -72 },
              { ip: '192.168.0.124', type: 'Tiltbridge', rssi: -60 },
          ]);
          setIsScanning(false);
      }, 2500);
  };

  const handleSelectScanned = (device: ScannedDevice) => {
      setDeviceToAddFromScan(device);
      setNewDeviceName(`Novo ${device.type}`); // Default Name
  };

  const handleSaveScanned = () => {
      if (deviceToAddFromScan && newDeviceName) {
          onAddFermenter({
              name: newDeviceName,
              ipAddress: deviceToAddFromScan.ip
          });
          setIsScanModalOpen(false);
          setDeviceToAddFromScan(null);
          setScannedDevices([]);
      }
  };

  return (
    <div className="p-6 max-w-7xl mx-auto animate-in fade-in duration-500">
      <header className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
            <h1 className="text-4xl font-light tracking-tight text-white mb-2">Dispositivos</h1>
            <p className="text-neutral-500 font-light">Gerenciamento de equipamentos e conexões</p>
        </div>
        <div className="flex flex-col md:items-end gap-2">
            <div className="text-xs text-neutral-600 font-mono mb-1">
                {fermenters.length} UNIDADES CONECTADAS
            </div>
            <div className="flex items-center gap-2">
                <button 
                    onClick={() => {
                        setIsScanModalOpen(true);
                        startScan();
                    }}
                    className="flex items-center gap-2 px-4 py-2 bg-neutral-800 hover:bg-neutral-700 text-white rounded-lg text-xs font-bold uppercase tracking-wide transition-all border border-neutral-700"
                >
                    <Search size={14} /> Procurar
                </button>
                <button 
                    onClick={() => setIsAddModalOpen(true)}
                    className="flex items-center gap-2 px-4 py-2 bg-neutral-100 hover:bg-white text-black rounded-lg text-xs font-bold uppercase tracking-wide transition-all"
                >
                    <Plus size={14} /> Adicionar
                </button>
            </div>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {fermenters.map((f) => {
             const tempDiff = Math.abs(f.currentDevice.temperature - f.targetTemp);

             // Check connectivity (Offline if no update > 30 mins)
             const lastUpdate = new Date(f.currentDevice.lastUpdate).getTime();
             const now = new Date().getTime();
             const isOnline = !isNaN(lastUpdate) && (now - lastUpdate) < 30 * 60 * 1000;

             // Lógica inteligente de Status/Rampa
             let statusLabel = 'Inativo';
             let dotColor = "bg-neutral-500";
             let textColor = "text-neutral-400";
             let containerClass = "bg-neutral-800/50 border-neutral-800";

             if (f.status !== FermenterStatus.IDLE) {
                 // Se tem perfil e índice válido, usa o nome da rampa
                 if (f.profile && f.profile.length > 0 && f.currentStepIndex < f.profile.length) {
                     statusLabel = f.profile[f.currentStepIndex].name;
                 } else {
                     // Caso contrário (modo manual ou erro), usa o status genérico
                     statusLabel = f.status;
                 }

                 // Definição de Cores
                 if (f.status === FermenterStatus.COLD_CRASH) {
                    dotColor = "bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.6)]";
                    textColor = "text-blue-400";
                    containerClass = "bg-blue-950/10 border-blue-900/30";
                 } else {
                    dotColor = "bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]";
                    textColor = "text-green-400";
                    containerClass = "bg-green-950/10 border-green-900/30";
                 }
             }

             return (
              <div 
                key={f.id} 
                onClick={() => onSelectFermenter(f.id)}
                className="group relative bg-neutral-900/40 hover:bg-neutral-900/60 border border-neutral-800 hover:border-neutral-700 rounded-3xl p-8 cursor-pointer transition-all duration-300 hover:shadow-2xl hover:shadow-black/50 overflow-hidden"
              >
                {/* Header Section: Name & ID & Actions */}
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <span className="block text-xs font-bold text-neutral-400 uppercase tracking-widest">
                            {f.name}
                        </span>
                        <span className="block text-[10px] font-mono text-neutral-600 mt-1">
                            {f.ipAddress || 'ID_UNKNOWN'}
                        </span>
                    </div>

                    <div className="flex items-center gap-3">
                        {/* Online/Offline Dot */}
                        <div 
                            title={isOnline ? "Online" : "Offline"}
                            className={`w-2 h-2 rounded-full transition-all duration-500 ${isOnline ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)] animate-pulse' : 'bg-red-500/50 border border-red-900'}`} 
                        />

                        <div className="flex items-center bg-neutral-800/50 rounded-lg p-1 border border-neutral-700/50">
                            <button 
                                onClick={(e) => handleDeleteClick(e, f.id)}
                                className="text-neutral-500 hover:text-red-500 hover:bg-red-500/10 p-1.5 rounded-md transition-all"
                                title="Excluir Dispositivo"
                            >
                                <Trash2 size={14} />
                            </button>
                            <div className="w-px h-3 bg-neutral-700/50 mx-1"></div>
                            <button 
                                onClick={(e) => handleEditClick(e, f)}
                                className="text-neutral-500 hover:text-white hover:bg-neutral-700 p-1.5 rounded-md transition-all"
                                title="Configurações"
                            >
                                <Settings size={14} />
                            </button>
                        </div>
                    </div>
                </div>

                <div className="mb-8">
                    {/* Beer Name - Mais encorpado e branco */}
                    <h2 className="text-3xl font-black text-white group-hover:text-white transition-colors truncate mb-3 tracking-tighter">
                        {f.beerName || 'Tanque Vazio'}
                    </h2>

                    {/* Smart Status Badge */}
                    <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full border ${containerClass} backdrop-blur-sm transition-all max-w-full`}>
                      <span className={`w-2 h-2 shrink-0 rounded-full ${dotColor} animate-pulse`}></span>
                      <span className={`text-[10px] font-medium uppercase tracking-widest ${textColor} truncate`}>
                        {statusLabel}
                      </span>
                    </div>
                </div>

                {/* Main Metrics - Clean & Large */}
                <div className="grid grid-cols-2 gap-8 mb-8">
                    {/* Temperature Column */}
                    <div className="relative">
                        <div className="flex items-start gap-1">
                            {/* Temperatura sempre branca */}
                            <span className="text-5xl font-light tracking-tighter text-white">
                                {f.currentDevice.temperature.toFixed(1)}
                            </span>
                            <span className="text-lg text-neutral-500 font-light mt-1">°C</span>
                        </div>
                        <div className="mt-2 flex items-center gap-2">
                             <div className="h-0.5 w-8 bg-neutral-700 rounded-full overflow-hidden">
                                <div className="h-full bg-neutral-400 w-1/2"></div>
                             </div>
                             <span className="text-xs text-neutral-500 font-mono">Alvo: {f.targetTemp.toFixed(1)}°</span>
                        </div>
                        {/* Sub-metric: Fridge */}
                        <div className="absolute -bottom-6 left-0 flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                             <Thermometer size={12} className="text-neutral-600" />
                             <span className="text-xs text-neutral-500">Geladeira: {f.currentFridgeTemp.toFixed(1)}°</span>
                        </div>
                    </div>

                    {/* Gravity Column */}
                    <div className="text-right">
                        <div className="flex items-start justify-end gap-1">
                             <span className="text-4xl font-light tracking-tighter text-purple-200">
                                {f.currentDevice.gravity.toFixed(3)}
                             </span>
                             <span className="text-lg text-neutral-500 font-light mt-1">SG</span>
                        </div>
                        <span className="text-xs text-neutral-500 uppercase tracking-wider block mt-2">
                            OG: {f.og.toFixed(3)}
                        </span>
                    </div>
                </div>

                {/* Footer Info - Minimalist (No Battery) */}
                <div className="flex items-center justify-between pt-6 border-t border-neutral-800/50 mt-auto">
                    <div className="flex gap-4">
                        <div className="flex items-center gap-1.5 text-neutral-600 group-hover:text-neutral-400 transition-colors" title="Sinal Wifi">
                            <Wifi size={14} />
                            <span className="text-xs font-mono">{f.currentDevice.rssi}</span>
                        </div>
                    </div>

                    <div className="w-8 h-8 rounded-full bg-neutral-800 flex items-center justify-center text-neutral-500 group-hover:bg-white group-hover:text-black transition-all duration-300">
                        <ArrowRight size={14} />
                    </div>
                </div>

                {/* Background Decor */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-neutral-800/10 to-transparent rounded-bl-full pointer-events-none"></div>
              </div>
             );
        })}
      </div>

      {/* MODAL 1: Edit Existing Device */}
      {editingId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-neutral-900 border border-neutral-800 p-6 rounded-2xl w-full max-w-sm shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-medium text-white">Editar Dispositivo</h3>
                    <button onClick={() => setEditingId(null)} className="text-neutral-500 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                <div className="space-y-4">
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">Nome do Equipamento</label>
                        <input 
                            type="text" 
                            value={editName}
                            onChange={(e) => setEditName(e.target.value)}
                            className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">IP / Serial</label>
                        <input 
                            type="text" 
                            value={editIp}
                            onChange={(e) => setEditIp(e.target.value)}
                            className="w-full bg-black border border-neutral-800 text-white font-mono text-sm rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                            placeholder="192.168.x.x"
                        />
                    </div>

                    <button 
                        onClick={handleSaveEdit}
                        className="w-full bg-white text-black font-medium py-3 rounded-xl mt-4 hover:bg-neutral-200 transition-colors flex items-center justify-center gap-2"
                    >
                        <Save size={18} /> Salvar Alterações
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* MODAL 4: Delete Confirmation */}
      {deletingId && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
              <div className="bg-neutral-900 border border-red-900/50 p-6 rounded-2xl w-full max-w-sm shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                  <div className="flex flex-col items-center text-center">
                      <div className="w-12 h-12 bg-red-500/10 rounded-full flex items-center justify-center text-red-500 mb-4">
                          <AlertTriangle size={24} />
                      </div>
                      <h3 className="text-xl font-medium text-white mb-2">Excluir Dispositivo?</h3>
                      <p className="text-neutral-400 text-sm mb-6">
                          Essa ação não pode ser desfeita. Todos os dados e logs deste fermentador serão perdidos permanentemente.
                      </p>

                      <div className="flex w-full gap-3">
                          <button 
                              onClick={() => setDeletingId(null)}
                              className="flex-1 bg-neutral-800 hover:bg-neutral-700 text-white py-3 rounded-xl font-medium transition-colors"
                          >
                              Cancelar
                          </button>
                          <button 
                              onClick={confirmDelete}
                              className="flex-1 bg-red-600 hover:bg-red-500 text-white py-3 rounded-xl font-medium transition-colors shadow-[0_0_15px_rgba(220,38,38,0.4)]"
                          >
                              Sim, Excluir
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL 2: Add Manual Device */}
      {isAddModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
             <div className="bg-neutral-900 border border-neutral-800 p-6 rounded-2xl w-full max-w-sm shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-medium text-white">Adicionar Manualmente</h3>
                    <button onClick={() => setIsAddModalOpen(false)} className="text-neutral-500 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                <div className="space-y-4">
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">Nome do Equipamento</label>
                        <input 
                            type="text" 
                            value={newDeviceName}
                            onChange={(e) => setNewDeviceName(e.target.value)}
                            placeholder="Ex: Fermentador 03"
                            className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">IP / Serial</label>
                        <input 
                            type="text" 
                            value={newDeviceIp}
                            onChange={(e) => setNewDeviceIp(e.target.value)}
                            placeholder="Ex: 192.168.1.50 ou SERIAL_123"
                            className="w-full bg-black border border-neutral-800 text-white font-mono text-sm rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                        />
                    </div>

                    <button 
                        onClick={handleManualAdd}
                        disabled={!newDeviceName || !newDeviceIp}
                        className="w-full bg-white text-black font-medium py-3 rounded-xl mt-4 hover:bg-neutral-200 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        <Plus size={18} /> Adicionar Dispositivo
                    </button>
                </div>
             </div>
          </div>
      )}

      {/* MODAL 3: Scan Network */}
      {isScanModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
             <div className="bg-neutral-900 border border-neutral-800 p-6 rounded-2xl w-full max-w-md shadow-2xl scale-100 animate-in zoom-in-95 duration-200 relative">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-medium text-white">Procurar na Rede</h3>
                    <button onClick={() => {
                        setIsScanModalOpen(false);
                        setDeviceToAddFromScan(null);
                        setScannedDevices([]);
                    }} className="text-neutral-500 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                {/* Sub-view: Enter Name for Scanned Device */}
                {deviceToAddFromScan ? (
                    <div className="space-y-4 animate-in slide-in-from-right duration-300">
                        <div className="bg-neutral-800/50 p-4 rounded-xl border border-neutral-700 flex items-center justify-between mb-4">
                            <div>
                                <p className="text-sm text-white font-medium">{deviceToAddFromScan.type}</p>
                                <p className="text-xs text-neutral-500 font-mono">{deviceToAddFromScan.ip}</p>
                            </div>
                            <div className="text-xs text-green-500 font-mono">{deviceToAddFromScan.rssi} dBm</div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-bold text-neutral-500 uppercase tracking-widest">Nomear Dispositivo</label>
                            <input 
                                type="text" 
                                value={newDeviceName}
                                onChange={(e) => setNewDeviceName(e.target.value)}
                                className="w-full bg-black border border-neutral-800 text-white rounded-xl px-4 py-3 focus:outline-none focus:border-neutral-600 transition-colors"
                                autoFocus
                            />
                        </div>

                        <div className="flex gap-2 mt-4">
                            <button 
                                onClick={() => setDeviceToAddFromScan(null)}
                                className="flex-1 bg-neutral-800 text-neutral-300 font-medium py-3 rounded-xl hover:bg-neutral-700 transition-colors"
                            >
                                Cancelar
                            </button>
                            <button 
                                onClick={handleSaveScanned}
                                disabled={!newDeviceName}
                                className="flex-1 bg-white text-black font-medium py-3 rounded-xl hover:bg-neutral-200 transition-colors disabled:opacity-50"
                            >
                                Salvar
                            </button>
                        </div>
                    </div>
                ) : (
                    /* Sub-view: List Scan Results */
                    <div className="min-h-[250px]">
                        {isScanning ? (
                            <div className="flex flex-col items-center justify-center h-64 space-y-4">
                                <div className="relative">
                                    <div className="absolute inset-0 bg-blue-500/20 blur-xl rounded-full animate-pulse"></div>
                                    <Loader2 size={48} className="text-blue-500 animate-spin relative z-10" />
                                </div>
                                <p className="text-neutral-400 text-sm animate-pulse">Escaneando rede local...</p>
                            </div>
                        ) : scannedDevices.length > 0 ? (
                            <div className="space-y-2">
                                <p className="text-xs text-neutral-500 mb-2 uppercase tracking-wide">Dispositivos Encontrados ({scannedDevices.length})</p>
                                {scannedDevices.map((device) => (
                                    <div key={device.ip} className="flex items-center justify-between bg-neutral-800/30 hover:bg-neutral-800 border border-neutral-800 hover:border-neutral-600 p-3 rounded-xl transition-all group">
                                        <div className="flex items-center gap-3">
                                            <div className="w-8 h-8 rounded-full bg-neutral-900 flex items-center justify-center text-neutral-500">
                                                <Smartphone size={16} />
                                            </div>
                                            <div>
                                                <p className="text-sm text-neutral-200 font-medium group-hover:text-white">{device.type}</p>
                                                <p className="text-[10px] text-neutral-600 font-mono">{device.ip}</p>
                                            </div>
                                        </div>
                                        <button 
                                            onClick={() => handleSelectScanned(device)}
                                            className="w-8 h-8 rounded-full bg-white text-black flex items-center justify-center hover:scale-110 transition-transform shadow-lg"
                                        >
                                            <Plus size={16} />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-64 text-center">
                                <Network size={48} className="text-neutral-800 mb-4" />
                                <p className="text-neutral-500 text-sm">Nenhum dispositivo encontrado.</p>
                                <button onClick={startScan} className="text-blue-500 text-xs mt-2 hover:underline">Tentar novamente</button>
                            </div>
                        )}
                    </div>
                )}
             </div>
          </div>
      )}
    </div>
  );
};

