          <div className="flex items-center gap-2">
            <Sparkles className="text-white" size={20} />
            <h3 className="text-lg font-bold text-neutral-100">Mestre Cervejeiro AI</h3>
          </div>
          {!insight && (
            <button
              onClick={handleAskAI}
