import { MOCK_FERMENTERS } from './services/mockData';
import { Fermenter, FermenterStatus, BeerStyle, DeviceMode } from './types';
import { History, LayoutDashboard, LogOut, Server } from 'lucide-react';

type ViewState = 'DASHBOARD' | 'HISTORY';
type AuthState = 'LOGIN' | 'REGISTER';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [authView, setAuthView] = useState<AuthState>('LOGIN');
  const [currentView, setCurrentView] = useState<ViewState>('DASHBOARD');
  const [fermenters, setFermenters] = useState<Fermenter[]>(MOCK_FERMENTERS);
  const [selectedFermenterId, setSelectedFermenterId] = useState<string | null>(null);

  // Auto-refresh simulation (mocking real-time WebSocket)
  useEffect(() => {
    if (!isAuthenticated) return;

    const interval = setInterval(() => {
        setFermenters(prev => prev.map(f => ({
            ...f,
            currentDevice: {
                ...f.currentDevice,
                lastUpdate: new Date().toISOString()
            }
        })));
    }, 30000); // Update every 30s
    return () => clearInterval(interval);
  }, [isAuthenticated]);

  const handleUpdateFermenter = (id: string, updates: Partial<Fermenter>) => {
    setFermenters(prev => prev.map(f => 
        f.id === id ? { ...f, ...updates } : f
    ));
  };

  const handleAddFermenter = (newDevice: Partial<Fermenter>) => {
    const newFermenter: Fermenter = {
        id: Math.random().toString(36).substr(2, 9),
        name: newDevice.name || 'Novo Dispositivo',
        ipAddress: newDevice.ipAddress || '',
        mode: DeviceMode.FERMENTER, // Default Mode
        status: FermenterStatus.IDLE,
        beerName: '',
        style: BeerStyle.LAGER, // Default
        startDate: '',
        og: 0,
        fg: 1.010,
        volume: 20,
        targetTemp: 20,
        readings: [],
        currentDevice: {
            gravity: 1.000,
            temperature: 20,
            battery: 0,
            angle: 0,
            rssi: 0,
            lastUpdate: ''
        },
        currentFridgeTemp: 20,
        profile: [],
        currentStepIndex: 0,
        isPaused: false,
        ...newDevice
    };
    setFermenters(prev => [...prev, newFermenter]);
  };

  const handleDeleteFermenter = (id: string) => {
    setFermenters(prev => prev.filter(f => f.id !== id));
    if (selectedFermenterId === id) {
        setSelectedFermenterId(null);
    }
  };

  const selectedFermenter = fermenters.find(f => f.id === selectedFermenterId);

  // Unauthenticated View
  if (!isAuthenticated) {
    if (authView === 'REGISTER') {
        return (
            <Register 
                onLogin={() => setIsAuthenticated(true)} 
                onSwitchToLogin={() => setAuthView('LOGIN')} 
            />
        );
    }
    return (
        <Login 
            onLogin={() => setIsAuthenticated(true)} 
            onSwitchToRegister={() => setAuthView('REGISTER')} 
        />
    );
  }

  // Authenticated Layout
  return (
    <div className="min-h-screen bg-black pb-10">
      {/* Navigation Bar */}
      <nav className="border-b border-neutral-800 bg-black/90 backdrop-blur sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div 
            className="flex items-center gap-3 cursor-pointer" 
            onClick={() => {
                setSelectedFermenterId(null);
                setCurrentView('DASHBOARD');
            }}
          >
            <div className="w-10 h-10 bg-gradient-to-br from-neutral-800 to-neutral-700 rounded-lg flex items-center justify-center border border-neutral-700 shadow-lg overflow-hidden">
                <img src="logo.svg" alt="BREWW Logo" className="w-full h-full object-cover" />
            </div>
            <span className="text-xl font-bold text-neutral-100 hidden sm:block">
                BREWW
            </span>
          </div>

          <div className="flex items-center gap-6">
             {/* Navigation Links */}
             <div className="flex bg-neutral-900/50 p-1 rounded-lg border border-neutral-800">
                <button 
                    onClick={() => {
                        setSelectedFermenterId(null);
                        setCurrentView('DASHBOARD');
                    }}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm font-medium transition-all ${currentView === 'DASHBOARD' && !selectedFermenterId ? 'bg-neutral-800 text-white border border-neutral-700 shadow-sm' : 'text-neutral-400 hover:text-white hover:bg-neutral-800'}`}
                >
                    <Server size={16} /> <span className="hidden sm:inline">Dispositivos</span>
                </button>
                <button 
                    onClick={() => {
                        setSelectedFermenterId(null);
                        setCurrentView('HISTORY');
                    }}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm font-medium transition-all ${currentView === 'HISTORY' ? 'bg-neutral-800 text-white border border-neutral-700 shadow-sm' : 'text-neutral-400 hover:text-white hover:bg-neutral-800'}`}
                >
                    <History size={16} /> <span className="hidden sm:inline">Logs</span>
                </button>
             </div>

             <div className="h-6 w-px bg-neutral-800 hidden sm:block"></div>

             <button 
                onClick={() => {
                    setIsAuthenticated(false);
                    setAuthView('LOGIN');
                }}
                className="text-neutral-500 hover:text-red-500 transition-colors"
                title="Sair"
             >
                <LogOut size={20} />
             </button>
          </div>
        </div>
      </nav>

      <main className="mt-6">
        {selectedFermenterId && selectedFermenter ? (
          <FermenterDetail 
            fermenter={selectedFermenter} 
            onBack={() => setSelectedFermenterId(null)}
            onUpdate={handleUpdateFermenter}
          />
        ) : currentView === 'HISTORY' ? (
          <FermentationHistory />
        ) : (
          <Dashboard 
            fermenters={fermenters} 
            onSelectFermenter={setSelectedFermenterId}
            onUpdateFermenter={handleUpdateFermenter}
            onAddFermenter={handleAddFermenter}
            onDeleteFermenter={handleDeleteFermenter}
          />
        )}
      </main>
    </div>
  );
};

export default App;

