import React, { useState } from 'react';
import { Fermenter, FermenterStatus, FermentationStep, DeviceMode, FermentationEvent } from '../types';
import { ArrowLeft, ThermometerSnowflake, Flame, PauseCircle, PlayCircle, Save, Settings2, Snowflake, Wifi, Clock, Percent, FlaskConical, Beer } from 'lucide-react';
