interface FermenterDetailProps {
  fermenter: Fermenter;
  onBack: () => void;
  onUpdate: (id: string, updates: Partial<Fermenter>) => void;
}

export const FermenterDetail: React.FC<FermenterDetailProps> = ({ fermenter, onBack, onUpdate }) => {
  // State for Temp
  const [targetTemp, setTargetTemp] = useState(fermenter.targetTemp);
  // States for Gravity Parameters
  const [targetOg, setTargetOg] = useState(fermenter.og);
  const [targetFg, setTargetFg] = useState(fermenter.fg || 1.010);

  const [isEditing, setIsEditing] = useState(false);

  const handleSave = () => {
    onUpdate(fermenter.id, { 
        targetTemp,
        og: targetOg,
        fg: targetFg
    });
    setIsEditing(false);
  };

  const handleModeChange = (mode: DeviceMode) => {
    onUpdate(fermenter.id, { mode });
  };

  const handleUpdateSteps = (newSteps: FermentationStep[]) => {
      onUpdate(fermenter.id, { profile: newSteps });
  };

  const handleAddEvent = (event: Omit<FermentationEvent, 'id'>) => {
    const newEvent: FermentationEvent = {
        ...event,
        id: Math.random().toString(36).substr(2, 9)
    };
    const updatedEvents = [...(fermenter.events || []), newEvent];
    onUpdate(fermenter.id, { events: updatedEvents });
  };

  const handleRemoveEvent = (id: string) => {
    const updatedEvents = (fermenter.events || []).filter(e => e.id !== id);
    onUpdate(fermenter.id, { events: updatedEvents });
  };

  // Profile Control Handlers
  const handleTogglePause = () => {
    onUpdate(fermenter.id, { isPaused: !fermenter.isPaused });
  };

  const handleNextStep = () => {
    if (fermenter.profile && fermenter.currentStepIndex < fermenter.profile.length - 1) {
        onUpdate(fermenter.id, { currentStepIndex: fermenter.currentStepIndex + 1 });
    }
  };

  const handleFinishProfile = () => {
      // Moves status to IDLE and stops the profile
      onUpdate(fermenter.id, { 
          status: FermenterStatus.IDLE, 
          isPaused: false,
          currentStepIndex: 0 
      });
  };

  // Calculations
  const abv = ((fermenter.og - fermenter.currentDevice.gravity) * 131.25).toFixed(1);

  const currentAttenuation = fermenter.og > 1.000 
    ? ((fermenter.og - fermenter.currentDevice.gravity) / (fermenter.og - 1.000) * 100).toFixed(0)
    : "0";

  const getStepTimeRemaining = () => {
      if (fermenter.status === FermenterStatus.IDLE || !fermenter.startDate || !fermenter.profile || fermenter.profile.length === 0) return '--';

      const start = new Date(fermenter.startDate).getTime();
      let daysPrior = 0;

      // Sum previous steps
      for (let i = 0; i < fermenter.currentStepIndex; i++) {
          daysPrior += fermenter.profile[i].duration;
      }

      // Add current step duration to calculate target end time of this step
      const currentDuration = fermenter.profile[fermenter.currentStepIndex]?.duration || 0;
      const targetEndTime = start + ((daysPrior + currentDuration) * 24 * 60 * 60 * 1000);
      const now = Date.now();
      const diff = targetEndTime - now;

      if (diff <= 0) return '0h';

      const d = Math.floor(diff / (1000 * 60 * 60 * 24));
      const h = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));

      return d > 0 ? `${d}d ${h}h` : `${h}h`;
  };

  return (
    <div className="p-6 md:p-8 max-w-7xl mx-auto animate-in fade-in duration-500">
      <button 
        onClick={onBack}
        className="flex items-center text-neutral-500 hover:text-white mb-8 transition-colors text-sm font-medium tracking-wide uppercase"
      >
        <ArrowLeft className="mr-2" size={16} /> Voltar
      </button>

      {/* Header Section Clean */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end mb-10 pb-6 border-b border-neutral-800/50">
        <div>
            <div className="flex items-center gap-3 mb-1">
                <span className={`w-2 h-2 rounded-full ${fermenter.currentDevice.lastUpdate ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-red-500'} animate-pulse`}></span>
                <span className="text-xs font-mono text-neutral-500 uppercase tracking-widest">{fermenter.name}</span>
            </div>
            <h1 className="text-5xl md:text-6xl font-black text-white tracking-tighter mb-2">{fermenter.beerName || 'Sem Nome'}</h1>
            <div className="flex items-center gap-4 text-sm text-neutral-500 font-light">
                <span className="bg-neutral-900 px-2 py-1 rounded text-neutral-400">{fermenter.style}</span>
                <span>Vol: {fermenter.volume}L</span>
                <span>Início: {fermenter.startDate ? new Date(fermenter.startDate).toLocaleDateString() : '--/--'}</span>
            </div>
        </div>

        <div className="flex bg-neutral-900 rounded-xl p-1.5 border border-neutral-800 mt-4 md:mt-0">
            <button 
                onClick={() => handleModeChange(DeviceMode.FERMENTER)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${
                    fermenter.mode === DeviceMode.FERMENTER 
                    ? 'bg-neutral-800 text-white shadow-sm border border-neutral-700' 
                    : 'text-neutral-500 hover:text-neutral-300'
                }`}
            >
                <FlaskConical size={14} /> Fermentador
            </button>
            <button 
                onClick={() => handleModeChange(DeviceMode.KEGERATOR)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${
                    fermenter.mode === DeviceMode.KEGERATOR 
                    ? 'bg-neutral-800 text-white shadow-sm border border-neutral-700' 
                    : 'text-neutral-500 hover:text-neutral-300'
                }`}
            >
                <Beer size={14} /> Choppeira
            </button>
            <button 
                onClick={() => handleModeChange(DeviceMode.FRIDGE)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${
                    fermenter.mode === DeviceMode.FRIDGE 
                    ? 'bg-neutral-800 text-white shadow-sm border border-neutral-700' 
                    : 'text-neutral-500 hover:text-neutral-300'
                }`}
            >
                <Snowflake size={14} /> Geladeira
            </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left Column: Charts & Events */}
        <div className="lg:col-span-2 space-y-4">
            <TemperatureChart data={fermenter.readings} events={fermenter.events} />

            {/* Event Log Component (Mini Cards Area) */}
            <EventLog 
                events={fermenter.events || []} 
                onAddEvent={handleAddEvent} 
                onRemoveEvent={handleRemoveEvent}
            />

            {fermenter.mode === DeviceMode.FERMENTER && (
                <GravityChart data={fermenter.readings} og={fermenter.og} fg={fermenter.fg} events={fermenter.events} />
            )}
            <GeminiAdvisor fermenter={fermenter} />
        </div>

        {/* Right Column: Metrics & Controls */}
        <div className="space-y-8">
            <div className="bg-neutral-900/30 rounded-3xl p-8 border border-neutral-800 backdrop-blur-sm relative overflow-hidden">
                <h3 className="text-neutral-500 text-xs font-bold uppercase tracking-widest mb-6">Telemetria em Tempo Real</h3>

                <div className="grid grid-cols-2 gap-8 mb-8">
                    <div>
                        <span className="block text-neutral-600 text-xs mb-1">Temperatura (Mosto)</span>
                        <div className="flex items-start gap-1">
                            <span className="text-4xl font-light text-white tracking-tighter">
                                {fermenter.currentDevice.temperature.toFixed(1)}
                            </span>
                            <span className="text-sm text-neutral-500 mt-1">°C</span>
                        </div>
                    </div>
                    <div>
                        <span className="block text-neutral-600 text-xs mb-1">Gravidade (SG)</span>
                        <div className="flex items-start gap-1">
                            <span className="text-4xl font-light text-purple-400 tracking-tighter">
                                {fermenter.currentDevice.gravity.toFixed(3)}
                            </span>
                            <span className="text-sm text-neutral-500 mt-1">SG</span>
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-3 gap-4 pt-6 border-t border-neutral-800/50">
                    <div className="text-center">
                        <Clock size={16} className="text-neutral-600 mx-auto mb-2" />
                        <span className="block text-[10px] font-bold text-neutral-600 uppercase mb-1">Fim da Rampa</span>
                        <span className="block text-sm font-mono text-white">{getStepTimeRemaining()}</span>
                    </div>
                    <div className="text-center border-l border-neutral-800/50">
                        <Percent size={16} className="text-neutral-600 mx-auto mb-2" />
                        <span className="block text-[10px] font-bold text-neutral-600 uppercase mb-1">Atenuação</span>
                        <span className="block text-sm font-mono text-blue-400">{currentAttenuation}%</span>
                    </div>
                    <div className="text-center border-l border-neutral-800/50">
                        <FlaskConical size={16} className="text-neutral-600 mx-auto mb-2" />
                        <span className="block text-[10px] font-bold text-neutral-600 uppercase mb-1">ABV Est.</span>
                        <span className="block text-sm font-mono text-green-500">{abv}%</span>
                    </div>
                </div>
            </div>

            {fermenter.mode === DeviceMode.FERMENTER && (
                <FermentationProfile 
                    steps={fermenter.profile || []} 
                    currentStepIndex={fermenter.currentStepIndex || 0}
                    isPaused={fermenter.isPaused || false}
                    onUpdateSteps={handleUpdateSteps}
                    onTogglePause={handleTogglePause}
                    onNextStep={handleNextStep}
                    onFinishProfile={handleFinishProfile}
                />
            )}

            <div className="bg-neutral-900/30 rounded-3xl p-6 border border-neutral-800 backdrop-blur-sm">
                <div className="flex justify-between items-center mb-6">
                    <span className="text-neutral-500 text-xs font-bold uppercase tracking-widest">
                        {isEditing ? 'Configurar Parâmetros' : 'Controle & Metas'}
                    </span>
                    <button onClick={() => isEditing ? handleSave() : setIsEditing(true)} className="text-neutral-400 hover:text-white transition-colors">
                        {isEditing ? <Save size={18} /> : <Settings2 size={18} />}
                    </button>
