                         <div className="text-right">
                            <span className="block text-[10px] text-neutral-600 uppercase font-bold mb-1">Meta FG</span>
                            {isEditing ? (
                                <input 
                                    type="number"
                                    value={targetFg}
                                    onChange={(e) => setTargetFg(parseFloat(e.target.value))}
                                    step="0.001"
                                    className="bg-transparent border-b border-neutral-600 text-lg font-mono text-white w-20 outline-none text-right"
                                />
                            ) : (
                                <span className="text-lg font-mono text-neutral-400">{fermenter.fg ? fermenter.fg.toFixed(3) : '-'}</span>
                            )}
                         </div>
                    </div>
                </div>
            </div>

        </div>
      </div>
    </div>
  );
};

