import React, { useState, useEffect } from 'react';
import { Dashboard } from './components/Dashboard';
import { FermenterDetail } from './components/FermenterDetail';
import { Login } from './components/Login';
import { Register } from './components/Register';
import { FermentationHistory } from './components/FermentationHistory';
import { MOCK_FERMENTERS } from './services/mockData';
import { Fermenter, FermenterStatus, BeerStyle, DeviceMode } from './types';
import { History, LayoutDashboard, LogOut, Server, Activity, Settings, LayoutGrid, ArrowLeft, Snowflake, Circle } from 'lucide-react';

type ViewState = 'DASHBOARD' | 'HISTORY' | 'SETTINGS';
type AuthState = 'LOGIN' | 'REGISTER';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [authView, setAuthView] = useState<AuthState>('LOGIN');
  const [currentView, setCurrentView] = useState<ViewState>('DASHBOARD');
  const [fermenters, setFermenters] = useState<Fermenter[]>(MOCK_FERMENTERS);
  const [selectedFermenterId, setSelectedFermenterId] = useState<string | null>(null);

  // Auto-refresh simulation (mocking real-time WebSocket)
  useEffect(() => {
    if (!isAuthenticated) return;

    const interval = setInterval(() => {
        setFermenters(prev => prev.map(f => ({
            ...f,
            currentDevice: {
                ...f.currentDevice,
                lastUpdate: new Date().toISOString()
            }
        })));
    }, 30000); // Update every 30s
    return () => clearInterval(interval);
  }, [isAuthenticated]);

  const handleUpdateFermenter = (id: string, updates: Partial<Fermenter>) => {
    setFermenters(prev => prev.map(f => 
        f.id === id ? { ...f, ...updates } : f
    ));
  };

  const handleAddFermenter = (newDevice: Partial<Fermenter>) => {
    const newFermenter: Fermenter = {
        id: Math.random().toString(36).substr(2, 9),
        name: newDevice.name || 'Novo Dispositivo',
        ipAddress: newDevice.ipAddress || '',
        mode: DeviceMode.FERMENTER,
        status: FermenterStatus.IDLE,
        beerName: '',
        style: BeerStyle.LAGER,
        startDate: '',
        og: 0,
        fg: 1.010,
        volume: 20,
        targetTemp: 20,
        readings: [],
        currentDevice: {
            gravity: 1.000,
            temperature: 20,
            battery: 0,
            angle: 0,
            rssi: 0,
            lastUpdate: ''
        },
        currentFridgeTemp: 20,
        profile: [],
        currentStepIndex: 0,
        isPaused: false,
        ...newDevice
    };
    setFermenters(prev => [...prev, newFermenter]);
  };

  const handleDeleteFermenter = (id: string) => {
    setFermenters(prev => prev.filter(f => f.id !== id));
    if (selectedFermenterId === id) {
        setSelectedFermenterId(null);
    }
  };

  const selectedFermenter = fermenters.find(f => f.id === selectedFermenterId);

  // Unauthenticated View
  if (!isAuthenticated) {
    if (authView === 'REGISTER') {
        return (
            <Register 
                onLogin={() => setIsAuthenticated(true)} 
                onSwitchToLogin={() => setAuthView('LOGIN')} 
            />
        );
    }
    return (
        <Login 
            onLogin={() => setIsAuthenticated(true)} 
            onSwitchToRegister={() => setAuthView('REGISTER')} 
        />
    );
  }

  // Header Button Styles following the requested image
  const headerBtnBase = "flex items-center gap-2 px-4 py-2 rounded-md text-[11px] font-bold uppercase tracking-wider border transition-all";
  const statusBtnActive = "border-green-500/50 text-green-500 bg-green-500/5";
  const coolingBtnActive = "border-blue-500/50 text-blue-500 bg-blue-500/5";
  const navBtnDefault = "border-neutral-800 text-neutral-400 hover:border-neutral-600 hover:text-white";
  const navBtnActive = "border-neutral-400 text-white bg-white/5";

  return (
    <div className="min-h-screen bg-black pb-10">
      {/* New Header based on image */}
      <nav className="bg-black py-6 px-8 no-print">
        <div className="max-w-[1600px] mx-auto flex items-center justify-between">

          {/* Logo BREWW Style */}
          <div 
            className="flex items-center cursor-pointer select-none" 
            onClick={() => {
                setSelectedFermenterId(null);
                setCurrentView('DASHBOARD');
            }}
          >
            <div className="flex items-baseline">
                <span className="text-4xl font-black text-white tracking-tighter">BREW</span>
                {/* Custom geometric W part */}
                <div className="relative">
                    <span className="text-4xl font-black text-white tracking-tighter">W</span>
                    <div className="absolute top-0 -right-2 w-3 h-2 bg-white rounded-tr-sm"></div>
                </div>
            </div>
          </div>

          {/* Right side controls */}
          <div className="flex items-center gap-3">

            {/* Status Badges */}
            <div className={`${headerBtnBase} ${statusBtnActive}`}>
                <Circle size={8} className="fill-current" />
                Online
            </div>

            <div className={`${headerBtnBase} ${coolingBtnActive}`}>
                <Snowflake size={14} />
                Resfriando
            </div>

            {/* Icon only settings */}
            <button className={`${headerBtnBase} border-neutral-800 text-neutral-400 px-3`}>
                <Settings size={16} />
            </button>

            {/* Main Nav */}
            <button 
                onClick={() => {
                    setSelectedFermenterId(null);
                    setCurrentView('DASHBOARD');
                }}
                className={`${headerBtnBase} ${currentView === 'DASHBOARD' && !selectedFermenterId ? navBtnActive : navBtnDefault}`}
            >
                <LayoutGrid size={14} />
                Grid
            </button>

            <button 
                onClick={() => {
                    setSelectedFermenterId(null);
                    setCurrentView('HISTORY');
                }}
                className={`${headerBtnBase} ${currentView === 'HISTORY' ? navBtnActive : navBtnDefault}`}
            >
                <History size={14} />
                Logs
            </button>

            <button 
                onClick={() => setCurrentView('SETTINGS')}
                className={`${headerBtnBase} ${currentView === 'SETTINGS' ? navBtnActive : navBtnDefault}`}
            >
                <Settings size={14} />
                Settings
            </button>

            {/* Conditional Back Button */}
            {selectedFermenterId && (
                <button 
                    onClick={() => setSelectedFermenterId(null)}
                    className={`${headerBtnBase} border-neutral-800 text-neutral-100 bg-neutral-900/40 hover:bg-neutral-800`}
                >
                    <ArrowLeft size={14} />
                    Voltar
                </button>
            )}

