import React from 'react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  ReferenceLine
} from 'recharts';
import { Reading, FermentationEvent } from '../types';

interface TemperatureChartProps {
  data: Reading[];
  events?: FermentationEvent[];
}

export const TemperatureChart: React.FC<TemperatureChartProps> = ({ data, events = [] }) => {
  // Map events to the closest data point's timestamp for alignment
  const eventMarks = events.map(event => {
    const eventTime = new Date(event.timestamp).getTime();
    const closest = data.reduce((prev, curr) => {
      return Math.abs(new Date(curr.timestamp).getTime() - eventTime) < 
             Math.abs(new Date(prev.timestamp).getTime() - eventTime) ? curr : prev;
    }, data[0]);
    return { ...event, markTime: closest?.timestamp };
  }).filter(e => e.markTime);

  return (
    <div className="w-full bg-neutral-900/30 p-8 rounded-3xl border border-neutral-800 backdrop-blur-sm overflow-hidden">
      <h3 className="text-neutral-500 font-bold mb-6 text-xs uppercase tracking-widest pl-2">Histórico de Temperatura</h3>
      {/* Fixed height container for Recharts */}
      <div className="w-full h-[350px]">
        <ResponsiveContainer width="100%" height="100%">
          <LineChart data={data}>
            <CartesianGrid strokeDasharray="3 3" stroke="#404040" vertical={false} strokeWidth={0.5} opacity={0.5} />
            <XAxis 
              dataKey="timestamp" 
              tickFormatter={(str) => new Date(str).toLocaleDateString(undefined, {day: '2-digit', month:'2-digit'})}
              stroke="#525252"
              fontSize={11}
              tickLine={false}
              axisLine={false}
              dy={10}
            />
            <YAxis 
              stroke="#525252" 
              domain={['auto', 'auto']} 
              fontSize={11} 
              unit="°" 
              tickLine={false}
              axisLine={false}
              dx={-10}
            />
            <Tooltip 
              contentStyle={{ backgroundColor: '#171717', borderColor: '#404040', color: '#f5f5f5', borderRadius: '16px', padding: '12px' }}
              itemStyle={{ color: '#d4d4d4', fontSize: '12px', paddingBottom: '4px' }}
              labelStyle={{ color: '#a3a3a3', fontSize: '10px', marginBottom: '8px', textTransform: 'uppercase', letterSpacing: '0.05em' }}
              labelFormatter={(label) => new Date(label).toLocaleString()}
              cursor={{ stroke: '#525252', strokeWidth: 0.5, strokeDasharray: '4 4' }}
            />
            <Legend wrapperStyle={{ paddingTop: '20px', fontSize: '12px' }} iconType="circle" />

            {eventMarks.map(e => (
              <ReferenceLine 
                key={e.id}
                x={e.markTime}
                stroke="rgba(255,255,255,0.3)"
                strokeWidth={1}
                label={{ 
                  value: e.type, 
                  position: 'insideTopLeft', 
                  fill: '#fff', 
                  fontSize: 9, 
                  fontWeight: 'bold',
                  offset: 5,
                  style: { textTransform: 'uppercase' }
                }}
              />
            ))}

            <Line 
              type="monotone" 
              dataKey="beerTemp" 
              name="Cerveja" 
              stroke="#ffffff" 
              strokeWidth={1.5} 
              dot={false} 
              activeDot={{ r: 4, strokeWidth: 0, fill: '#ffffff' }}
            />
            <Line 
              type="monotone" 
              dataKey="targetTemp" 
              name="Set Point" 
              stroke="#22c55e" 
              strokeDasharray="4 4" 
              strokeWidth={1} 
              dot={false} 
            />
             <Line 
              type="monotone" 
              dataKey="fridgeTemp" 
              name="Geladeira" 
              stroke="#3b82f6" 
              strokeWidth={1} 
              dot={false} 
              opacity={0.5}
            />
          </LineChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

import React from 'react';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  ReferenceLine
} from 'recharts';
import { Reading, FermentationEvent } from '../types';

interface GravityChartProps {
  data: Reading[];
  og?: number;
  fg?: number;
  events?: FermentationEvent[];
}

export const GravityChart: React.FC<GravityChartProps> = ({ data, og, fg, events = [] }) => {
  if (!data || data.length === 0) return null;

  // Calculate domain to ensure OG and FG are visible
  const dataMin = Math.min(...data.map(d => d.gravity));
  const dataMax = Math.max(...data.map(d => d.gravity));

  // Extend domain to include targets if they exist
  const finalMin = fg ? Math.min(dataMin, fg) : dataMin;
  const finalMax = og ? Math.max(dataMax, og) : dataMax;

  // Map events to chart data points
  const eventMarks = events.map(event => {
    const eventTime = new Date(event.timestamp).getTime();
    const closest = data.reduce((prev, curr) => {
      return Math.abs(new Date(curr.timestamp).getTime() - eventTime) < 
             Math.abs(new Date(prev.timestamp).getTime() - eventTime) ? curr : prev;
    }, data[0]);
    return { ...event, markTime: closest?.timestamp };
  }).filter(e => e.markTime);

  return (
    <div className="w-full bg-neutral-900/30 p-8 rounded-3xl border border-neutral-800 backdrop-blur-sm overflow-hidden">
      <h3 className="text-neutral-500 font-bold mb-6 text-xs uppercase tracking-widest pl-2">Curva de Atenuação (Gravidade)</h3>
      {/* Fixed height container for Recharts */}
      <div className="w-full h-[350px]">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={data}>
            <defs>
              <linearGradient id="colorGravity" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#8b5cf6" stopOpacity={0.2}/>
                <stop offset="95%" stopColor="#8b5cf6" stopOpacity={0}/>
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="#404040" vertical={false} strokeWidth={0.5} opacity={0.5} />
            <XAxis 
               dataKey="timestamp" 
               tickFormatter={(str) => new Date(str).toLocaleDateString(undefined, {day: '2-digit', month:'2-digit'})}
               stroke="#525252"
               fontSize={11}
               tickLine={false}
               axisLine={false}
               dy={10}
            />
            <YAxis 
              stroke="#525252" 
              domain={[finalMin - 0.002, finalMax + 0.002]} 
              fontSize={11} 
              tickFormatter={(val) => val.toFixed(3)} 
              tickLine={false}
              axisLine={false}
              dx={-10}
            />
            <Tooltip 
              contentStyle={{ backgroundColor: '#171717', borderColor: '#404040', color: '#f5f5f5', borderRadius: '16px', padding: '12px' }}
              itemStyle={{ color: '#d4d4d4', fontSize: '12px', paddingBottom: '4px' }}
              labelStyle={{ color: '#a3a3a3', fontSize: '10px', marginBottom: '8px', textTransform: 'uppercase', letterSpacing: '0.05em' }}
              labelFormatter={(label) => new Date(label).toLocaleString()}
              formatter={(value: number) => [value.toFixed(3), 'SG']}
              cursor={{ stroke: '#525252', strokeWidth: 0.5, strokeDasharray: '4 4' }}
            />
            <Legend wrapperStyle={{ paddingTop: '20px', fontSize: '12px' }} iconType="circle" />

            {og && (
              <ReferenceLine 
                  y={og} 
                  stroke="#737373" 
                  strokeDasharray="3 3" 
                  strokeWidth={1}
                  label={{ position: 'insideTopRight', value: `OG: ${og.toFixed(3)}`, fill: '#737373', fontSize: 10, fontWeight: 600 }} 
              />
            )}
            {fg && (
              <ReferenceLine 
                  y={fg} 
                  stroke="#ffffff" 
                  strokeDasharray="3 3" 
                  strokeWidth={1}
                  label={{ position: 'insideBottomRight', value: `Meta FG: ${fg.toFixed(3)}`, fill: '#ffffff', fontSize: 10, fontWeight: 600 }} 
              />
            )}

            {eventMarks.map(e => (
              <ReferenceLine 
                key={e.id}
                x={e.markTime}
                stroke="rgba(255,255,255,0.3)"
                strokeWidth={1}
                label={{ 
                  value: e.type, 
                  position: 'insideTopLeft', 
                  fill: '#fff', 
                  fontSize: 9, 
                  fontWeight: 'bold',
                  offset: 5,
                  style: { textTransform: 'uppercase' }
                }}
              />
            ))}

            <Area 
              type="monotone" 
              dataKey="gravity" 
              name="Gravidade (SG)" 
              stroke="#8b5cf6" 
              fillOpacity={1} 
              fill="url(#colorGravity)" 
              strokeWidth={1.5}
              activeDot={{ r: 4, strokeWidth: 0, fill: '#8b5cf6' }}
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Fermenter, FermenterStatus, FermentationStep, DeviceMode, FermentationEvent } from '../types';
import { ThermometerSnowflake, Flame, PauseCircle, PlayCircle, Save, Settings2, Snowflake, Wifi, Clock, Percent, FlaskConical, Beer } from 'lucide-react';
import { TemperatureChart } from './TemperatureChart';
import { GravityChart } from './GravityChart';
import { GeminiAdvisor } from './GeminiAdvisor';
import { FermentationProfile } from './FermentationProfile';
import { EventLog } from './EventLog';

interface FermenterDetailProps {
  fermenter: Fermenter;
  onUpdate: (id: string, updates: Partial<Fermenter>) => void;
}

export const FermenterDetail: React.FC<FermenterDetailProps> = ({ fermenter, onUpdate }) => {
  // State for Temp
  const [targetTemp, setTargetTemp] = useState(fermenter.targetTemp);
  // States for Gravity Parameters
  const [targetOg, setTargetOg] = useState(fermenter.og);
  const [targetFg, setTargetFg] = useState(fermenter.fg || 1.010);

  const [isEditing, setIsEditing] = useState(false);

  const handleSave = () => {
    onUpdate(fermenter.id, { 
        targetTemp,
        og: targetOg,
        fg: targetFg
    });
    setIsEditing(false);
  };

  const handleModeChange = (mode: DeviceMode) => {
    onUpdate(fermenter.id, { mode });
  };

  const handleUpdateSteps = (newSteps: FermentationStep[]) => {
      onUpdate(fermenter.id, { profile: newSteps });
  };

  const handleAddEvent = (event: Omit<FermentationEvent, 'id'>) => {
    const newEvent: FermentationEvent = {
        ...event,
        id: Math.random().toString(36).substr(2, 9)
    };
    const updatedEvents = [...(fermenter.events || []), newEvent];
    onUpdate(fermenter.id, { events: updatedEvents });
  };

  const handleRemoveEvent = (id: string) => {
    const updatedEvents = (fermenter.events || []).filter(e => e.id !== id);
    onUpdate(fermenter.id, { events: updatedEvents });
  };

  // Profile Control Handlers
  const handleTogglePause = () => {
    onUpdate(fermenter.id, { isPaused: !fermenter.isPaused });
  };

  const handleNextStep = () => {
    if (fermenter.profile && fermenter.currentStepIndex < fermenter.profile.length - 1) {
        onUpdate(fermenter.id, { currentStepIndex: fermenter.currentStepIndex + 1 });
    }
  };

  const handleFinishProfile = () => {
      // Moves status to IDLE and stops the profile
      onUpdate(fermenter.id, { 
          status: FermenterStatus.IDLE, 
          isPaused: false,
          currentStepIndex: 0 
      });
  };

  // Calculations
  const abv = ((fermenter.og - fermenter.currentDevice.gravity) * 131.25).toFixed(1);

  const currentAttenuation = fermenter.og > 1.000 
    ? ((fermenter.og - fermenter.currentDevice.gravity) / (fermenter.og - 1.000) * 100).toFixed(0)
    : "0";

  const getStepTimeRemaining = () => {
      if (fermenter.status === FermenterStatus.IDLE || !fermenter.startDate || !fermenter.profile || fermenter.profile.length === 0) return '--';

      const start = new Date(fermenter.startDate).getTime();
      let daysPrior = 0;

      // Sum previous steps
      for (let i = 0; i < fermenter.currentStepIndex; i++) {
          daysPrior += fermenter.profile[i].duration;
      }

      // Add current step duration to calculate target end time of this step
      const currentDuration = fermenter.profile[fermenter.currentStepIndex]?.duration || 0;
      const targetEndTime = start + ((daysPrior + currentDuration) * 24 * 60 * 60 * 1000);
      const now = Date.now();
      const diff = targetEndTime - now;

      if (diff <= 0) return '0h';

      const d = Math.floor(diff / (1000 * 60 * 60 * 24));
      const h = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));

      return d > 0 ? `${d}d ${h}h` : `${h}h`;
  };

  return (
    <div className="p-6 md:p-8 max-w-7xl mx-auto animate-in fade-in duration-500">
      {/* Header Section Clean */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end mb-10 pb-6 border-b border-neutral-800/50">
        <div>
            <div className="flex items-center gap-3 mb-1">
                <span className={`w-2 h-2 rounded-full ${fermenter.currentDevice.lastUpdate ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-red-500'} animate-pulse`}></span>
                <span className="text-xs font-mono text-neutral-500 uppercase tracking-widest">{fermenter.name}</span>
            </div>
            <h1 className="text-5xl md:text-6xl font-black text-white tracking-tighter mb-2">{fermenter.beerName || 'Sem Nome'}</h1>
            <div className="flex items-center gap-4 text-sm text-neutral-500 font-light">
                <span className="bg-neutral-900 px-2 py-1 rounded text-neutral-400">{fermenter.style}</span>
                <span>Vol: {fermenter.volume}L</span>
