            <div className="flex items-center gap-4 text-sm text-neutral-500 font-light">
                <span className="bg-neutral-900 px-2 py-1 rounded text-neutral-400">{fermenter.style}</span>
                <span>Vol: {fermenter.volume}L</span>
                <span>Início: {fermenter.startDate ? new Date(fermenter.startDate).toLocaleDateString() : '--/--'}</span>
            </div>
        </div>

        <div className="flex bg-neutral-900 rounded-xl p-1.5 border border-neutral-800 mt-4 md:mt-0">
            <button 
                onClick={() => handleModeChange(DeviceMode.FERMENTER)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${
                    fermenter.mode === DeviceMode.FERMENTER 
                    ? 'bg-neutral-800 text-white shadow-sm border border-neutral-700' 
                    : 'text-neutral-500 hover:text-neutral-300'
                }`}
            >
                <FlaskConical size={14} /> Fermentador
            </button>
            <button 
                onClick={() => handleModeChange(DeviceMode.KEGERATOR)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${
                    fermenter.mode === DeviceMode.KEGERATOR 
