    setSettings(prev => ({ ...prev, [field]: value }));
  };

  const handlePIDChange = (type: 'pidHeating' | 'pidCooling', param: keyof PIDParams, value: number) => {
    setSettings(prev => ({
      ...prev,
      [type]: { ...prev[type], [param]: value }
